window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q16"]=window.__LIBQ["tien-nghich"]["q16"]||{};window.__LIBQ["tien-nghich"]["q16"]["techniques"]={"updatedAt":"2026-07-15","count":67,"techniques":[{"id":"ngu-hanh-quy-nhat-tran","name":"Ngũ Hành Quy Nhất trận","cn":"","aliases":["Ngũ hành đại trận","Ngũ Hành đại trận"],"loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ (cấp tinh cầu)","hePhai":"Quy Nhất Tông","soHuu":["Quy Nhất Tông"],"blurb":"Ngũ Hành Quy Nhất trận là đại trận hộ tinh cấp tinh cầu của Ngũ Hành tinh, tạo bởi năm quầng sáng ngũ sắc xoay tròn bao quanh tinh cầu, chứa lực lượng Ngũ Hành liên tục công kích kẻ xâm nhập. Cường giả Quy Nhất Tông tự nhận lọt vào chỉ chống đỡ được nửa nén nhang.","detail":"Trận pháp hộ tinh cấp tinh cầu bố trí trên Ngũ Hành tinh, thuộc phạm vi của Quy Nhất Tông. Năm quầng sáng ngũ sắc xoay tròn bao bọc toàn bộ tinh cầu, bên trong chứa năm loại lực lượng Ngũ Hành gồm hỏa diễm, hàn thủy, kim lực, thổ và mộc khí, liên tục công kích bất kỳ kẻ nào xâm nhập. Đại trận chia thành năm quan thử thách (ngũ quan); nếu người xâm nhập vượt qua hết cả năm quan, trận pháp sẽ diễn biến thành dạng thức cao hơn là Ngũ Hành quy nhất cửu chuyển. Cường giả tầng cao của Quy Nhất Tông tự thừa nhận rằng lọt vào trận cũng chỉ chống đỡ được nửa nén nhang, dừng lại ở hỏa hoành quang. Vương Lâm từng bước vào quầng sáng ngũ sắc của đại trận này và chịu công kích liên tiếp từ lực lượng Ngũ Hành.","congNang":["Trận pháp hộ tinh cấp tinh cầu, bao bọc toàn bộ Ngũ Hành tinh bằng năm quầng sáng ngũ sắc xoay tròn","Liên tục công kích kẻ xâm nhập bằng lực lượng Ngũ Hành gồm hỏa diễm, hàn thủy, kim lực, thổ và mộc khí @c1634","Thiết lập năm quan thử thách (ngũ quan) cho kẻ xâm nhập","Diễn biến thành Ngũ Hành quy nhất cửu chuyển nếu người xâm nhập qua hết ngũ quan"],"dacDiem":"Ngũ sắc xoay tròn quanh tinh cầu, lực lượng Ngũ Hành gồm hỏa diễm, hàn thủy, kim lực, thổ, mộc khí; chia ngũ quan và có thể diễn biến thành cửu chuyển.","uyLuc":"Cường giả tầng cao Quy Nhất Tông tự nhận lọt vào trận cũng chỉ chống đỡ được nửa nén nhang, dừng ở hỏa hoành quang.","tabs":{"tienTrinh":[{"chuong":"@c1634","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm bước vào trận","text":"Vương Lâm bước vào quầng sáng ngũ sắc của Ngũ Hành đại trận, chịu công kích liên tiếp từ lực lượng Ngũ Hành. Lão già hắc bào tầng cao tháp tuyên bố trận pháp cực lợi hại, bản thân lọt vào cũng chỉ chống đỡ nửa nén nhang.","anchor":"Ngũ Hành đại trận này dù là lão phu lọt vào cũng chỉ có thể chống đỡ trong thời gian nửa nén nhang mà thôi"}]},"nguon":["@c1634"]},{"id":"dai-dia-tho-tran","name":"Đại địa thổ trận","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Quy Nhất tông","soHuu":["Quy Nhất tông"],"blurb":"Đại địa thổ trận là trận đầu tiên trong Ngũ hành đại trận bảo vệ Ngũ Hành tinh, do chín vị lão tổ Quy Nhất tông đồng thời bày ra. Bên trong trận chỉ có đại địa phía trên và dưới, không có bầu trời, tổng cộng gồm chín biến với mỗi biến mạnh hơn biến trước. Vương Lâm đã dùng thân thể Đạo cổ phá sơ biến và đệ nhị biến, đồng thời thu luôn trận linh của trận này.","detail":"Đại địa thổ trận là trận thứ nhất trong năm quan của Ngũ hành đại trận, hệ thống phòng ngự bảo vệ Ngũ Hành tinh. Trận do chín vị lão tổ Quy Nhất tông cùng nhau bày bố. Khi trận kích hoạt, mục tiêu bị đưa vào một không gian chỉ tồn tại đại địa phía trên lẫn phía dưới, hoàn toàn không có bầu trời. Trận gồm tổng cộng chín biến, mỗi biến uy lực mạnh hơn biến trước. Sơ biến tạo ra chín cơn lốc hóa thành chín mặt người bùn đất tấn công mục tiêu. Đệ nhị biến khiến hai mặt đất trên dưới ép chặt vào nhau, không còn khe hở, nghiền nát mục tiêu. Khi Vương Lâm đối mặt trận này, hắn dùng thân thể Đạo cổ tung chín quyền phá toàn bộ chín mặt người đất của sơ biến, rồi tiếp tục phá đệ nhị biến hai mặt đất ép, đồng thời thu luôn trận linh — một dúm bùn đất tỏa linh khí dày đặc.","congNang":["Tạo không gian trận chỉ có đại địa phía trên và dưới, hoàn toàn không có bầu trời, giam giữ mục tiêu @c1635","Sơ biến: triệu hồi chín cơn lốc hóa thành chín mặt người bùn đất tấn công mục tiêu @c1635","Đệ nhị biến: hai mặt đất trên dưới ép chặt mục tiêu, không còn khe hở @c1635"],"nguonGoc":"Do chín vị lão tổ Quy Nhất tông đồng thời bày ra","dacDiem":"Gồm chín biến, mỗi biến mạnh hơn biến trước; không gian trận chỉ có đại địa trên dưới, không có bầu trời; trận linh là một dúm bùn đất tỏa linh khí dày đặc.","trangThai":"Bị phá, trận linh bị Vương Lâm thu","capNhatToi":"@c1635","tabs":{"tienTrinh":[{"chuong":"@c1635","loai":"dùng","importance":"major","giaiDoan":"Bị Vương Lâm phá và thu trận linh","text":"Vương Lâm đối mặt trận thứ nhất, tung chín quyền phá chín mặt người đất sơ biến, bị đệ nhị biến hai mặt đất ép chặt nhưng đấm vỡ từ bên trong, thu luôn trận linh.","anchor":"Chúng hóa thành một dúm đất! Một dúm bùn đất này tỏa ra linh khí dày đặc, chính là trận linh của Ngũ hành đại trận"}]},"nguon":["@c1635"]},{"id":"ngu-hanh-hoa-tran","name":"Ngũ Hành hỏa trận","cn":"五行火阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Quy Nhất tông","soHuu":["Quy Nhất tông"],"blurb":"Ngũ Hành hỏa trận là trận pháp thuộc hệ hỏa trong Ngũ Hành đại trận của Quy Nhất tông. Trận pháp sở hữu người khổng lồ lửa và chín Kỳ Lân lửa, nhưng bị Vương Lâm đứng trên đỉnh đầu người khổng lồ lửa chỉ huy phá nát, cảnh tượng sau đó chuyển sang Ngũ Hành thủy trận.","detail":"Ngũ Hành hỏa trận là một trong năm trận thành phần cấu thành Ngũ Hành đại trận. Bên trong trận có người khổng lồ lửa và chín Kỳ Lân lửa. Khi Vương Lâm đối mặt hỏa trận, hắn đứng trên đỉnh đầu người khổng lồ lửa và chỉ huy nó vung tay phá nát trận pháp; hỏa trận ầm ầm sụp đổ, cảnh tượng biến đổi chuyển tiếp sang Ngũ Hành thủy trận.","trangThai":"Bị phá","congNang":["Bên trong trận tồn tại người khổng lồ lửa và chín Kỳ Lân lửa","Là một phần của Ngũ Hành đại trận, bị phá thì cảnh tượng tự động chuyển sang trận kế tiếp — Ngũ Hành thủy trận @c1637"],"tabs":{"tienTrinh":[{"chuong":"@c1637","loai":"nhắc tới","importance":"major","giaiDoan":"Bị phá sập","text":"Vương Lâm chỉ huy người khổng lồ lửa vung tay phá nát hỏa trận, cảnh tượng chuyển sang thủy trận.","anchor":"Một cái vung này liền khiến cho hỏa trận ầm ầm sụp đổ"}]},"capNhatToi":"@c1637","nguon":["@c1637"],"uyLuc":"Người khổng lồ lửa trong trận đủ mạnh để Vương Lâm chiếm đoạt và dùng chính nó vung tay phá nát toàn bộ hỏa trận, khiến trận ầm ầm sụp đổ @c1637.","dacDiem":"Thuộc hệ hỏa, là bộ phận của Ngũ Hành đại trận; khi bị phá, không tiêu tán mà tự động chuyển cảnh sang trận tiếp theo trong chuỗi ngũ hành."},{"id":"ngu-hanh-thuy-tran","name":"Ngũ Hành thủy trận","cn":"五行水阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Quy Nhất tông","soHuu":["Quy Nhất tông"],"blurb":"Trận pháp thuộc hệ thủy trong Ngũ Hành đại trận của Quy Nhất tông, hiện ra hải dương vô tận với sóng gió mây đen dày đặc. Thủy Tướng sở hữu thân thể thủy linh Ngũ Hành hoàn chỉnh đóng vai trò linh hồn trận, khiến uy lực gia tăng gấp bội.","detail":"Ngũ Hành thủy trận là trận pháp kích hoạt tiếp sau khi hỏa trận trong Ngũ Hành đại trận của Quy Nhất tông bị phá. Khi trận khởi động, không gian hiện ra hải dương vô tận, sóng gió cuồn cuộn, mây đen dày đặc che phủ, mưa to gào thét. Thủy Tướng với thân thể thủy linh Ngũ Hành hoàn chỉnh chính là linh hồn của thủy trận, nhờ đó uy lực trận pháp được gia tăng gấp bội so với thông thường. Trong trận, Thủy Tướng triển khai bốn bức tường nước cao vạn trượng bao vây đối thủ, đồng thời sử dụng trường thương nước mưa huyễn hóa hợp nhất với bản thân để chiến đấu.","thuocTinh":"Thủy","congNang":["Thủy Tướng có thân thể thủy linh Ngũ Hành hoàn chỉnh làm linh hồn trận, khiến uy lực trận pháp gấp bội @c1637","Bốn bức tường nước cao vạn trượng bao vây đối thủ @c1637","Trường thương nước mưa huyễn hóa hợp nhất với thân Thủy Tướng @c1637"],"tabs":{"tienTrinh":[{"chuong":"@c1637","loai":"xuất hiện","importance":"major","giaiDoan":"Kích hoạt sau khi hỏa trận bị phá","text":"Thủy trận kích hoạt, Thủy Tướng xuất hiện là linh hồn trận, dùng bốn bức tường nước vạn trượng và trường thương nước mưa nhấn chìm Vương Lâm trong biển.","anchor":"Có hắn ở đây, uy lực thủy trận sẽ gia tăng gấp bội"}]},"capNhatToi":"@c1637","nguon":["@c1637"],"uyLuc":"Thủy Tướng với thân thủy linh hoàn chỉnh làm linh hồn trận, uy lực gia tăng gấp bội, triển khai bốn bức tường nước vạn trượng phong tỏa đối thủ trong hải dương vô tận.","dacDiem":"Trận pháp hiện ra hải dương vô tận với sóng gió, mây đen dày đặc và mưa to gào thét; Thủy Tướng vừa là linh hồn trận vừa trực tiếp tham chiến, thân thể thủy linh hoàn chỉnh hợp nhất cùng trận pháp."},{"id":"can-khon-nhat-tich","name":"Càn Khôn Nhất Tích","cn":"乾坤一滴","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thủy","soHuu":["Thủy Tướng"],"blurb":"Càn Khôn Nhất Tích là thần thông cổ truyền từ tổ tiên Thủy Tướng, theo phương pháp Quy Nhất tông trên Tiên Cương đại lục. Người thi triển dùng thân thể thủy linh ngưng tụ toàn bộ nước biển và nước mưa thành quả cầu khổng lồ rồi co rút thành một giọt chứa lực lượng thủy bổn nguyên, ép nát mọi thứ bên trong. Đây là chiêu thức đánh đổi toàn bộ lực lượng của bản thân, khiến người dùng suy kiệt hoàn toàn sau khi thi triển.","detail":"Càn Khôn Nhất Tích có nguồn gốc từ tổ tiên của Thủy Tướng, tu luyện theo phương pháp Quy Nhất tông trên Tiên Cương đại lục. Khi thi triển, Thủy Tướng phun máu bắt quyết, vận dụng thân thể thủy linh ngưng tụ thủy lực Ngũ Hành, nâng toàn bộ hải dương lên trời đồng thời phá tan mây đen khiến nước mưa đổ xuống, dung hợp nước biển và nước mưa thành quả cầu nước khổng lồ bao trùm mục tiêu. Quả cầu liên tục co rút, áp lực tăng vô số lần; nếu luyện hóa hoàn toàn thành một giọt duy nhất thì tinh không bên trong cũng bị ép tan — đây chính là lực lượng thủy bổn nguyên. Cái giá phải trả vô cùng lớn: người thi triển tuôn hết toàn bộ lực lượng áo giáp, thân thể héo rũ nổi mụn mủ, lộ ra hình dạng thật.","thuocTinh":"Thủy","nguonGoc":"Tổ tiên Thủy Tướng truyền, theo phương pháp Quy Nhất tông trên Tiên Cương đại lục","uyLuc":"Co nén toàn bộ nước thành một giọt chứa thủy bổn nguyên, dù tinh không bên trong cũng bị ép tan.","dacDiem":"Người thi triển phải tuôn hết toàn bộ lực lượng áo giáp, thân thể suy kiệt héo rũ nổi mụn mủ và lộ hình dạng thật sau khi dùng — là chiêu thức đánh đổi tất cả, chỉ có thể tung ra một lần.","congNang":["Ngưng tụ toàn bộ nước biển và nước mưa thành quả cầu nước khổng lồ bao trùm mục tiêu @c1638","Co rút quả cầu nước liên tục, áp lực tăng vô số lần, cuối cùng luyện hóa thành một giọt chứa lực lượng thủy bổn nguyên @c1638","Ép nát mục tiêu bên trong giọt nước, tinh không cũng bị ép tan khi hoàn thành co nén @c1638"],"nguoiTu":[{"ten":"Thủy Tướng","tuChuong":"@c1638","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1638","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Thủy Tướng phun máu bắt quyết, dùng thân thể thủy linh ngưng tụ toàn bộ nước biển và nước mưa thành quả cầu khổng lồ nhốt Vương Lâm, co rút ép nén. Tuôn hết lực lượng áo giáp, thân thể héo rũ lộ hình dạng thật. Tuy nhiên Vương Lâm chọn ở lại bên trong cảm ngộ thủy bổn nguyên thay vì thoát ra.","anchor":"Càn khôn nhất tích!"}]},"nguon":["@c1638"]},{"id":"cuu-chuyen-tam-luan","name":"Cửu Chuyển Tâm Luân","cn":"九轉心輪","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Trận pháp hộ sơn Quy Nhất tông","hePhai":"Quy Nhất tông","soHuu":["Quy Nhất tông","Đệ Cửu lão tổ"],"blurb":"Cửu Chuyển Tâm Luân là trận pháp hộ sơn tối hậu của Quy Nhất tông, kích hoạt sau khi Ngũ Hành đại trận bị phá. Trận pháp dựa hoàn toàn vào tâm cảnh của người bị nhốt: tâm bất động thì phá được, tâm dao động thì bị cuốn vào chín chuyển, tiêu hao tâm thần cho tới khi tử vong.","detail":"Cửu Chuyển Tâm Luân do Quy Nhất tông sáng chế, bản gốc đặt tại tổng đàn trên Tiên Cương đại lục. Bản bố trí tại Ngũ Hành tinh chỉ có bốn phần uy lực so với đại trận gốc, nhưng vẫn đủ sức giữ chân cường giả nếu tâm cảnh đối phương dao động. Trận pháp kích hoạt khi Ngũ Hành tinh bắt đầu chuyển động, dùng ảo cảnh xoay tròn của năm ngôi sao tác động trực tiếp lên thần thức, kể cả nhắm mắt vẫn bị ảnh hưởng. Cơ chế vận hành theo nguyên lý chín chuyển: cứ mỗi chín nhịp thở là một chuyển, tâm động càng mạnh thì tốc độ xoay càng nhanh, tổng cộng chín chuyển. Chỉ cần đối phương không nhìn ra dấu vết phá trận ngay từ đầu và bị cuốn vào một chuyển, thì nhất định không thể tự phá nổi. Vương Lâm sau khi phá xong toàn bộ Ngũ Hành đại trận đã bị trận pháp này kích hoạt, trải qua từ đệ nhất chuyển tới đệ c","thuocTinh":"Tâm cảnh","nguonGoc":"Quy Nhất tông sáng chế, bản gốc đặt tại Tiên Cương đại lục","dacDiem":"Dựa vào tâm bất động làm cốt lõi, mỗi chín nhịp thở là một chuyển, bị cuốn vào một chuyển thì không phá nổi; ảo cảnh truyền qua thần thức nên nhắm mắt cũng không tránh được.","uyLuc":"Bản tại Ngũ Hành tinh chỉ có bốn phần uy lực so với bản gốc trên Tiên Cương đại lục, nhưng vẫn đủ sức giữ chân cường giả nếu tâm cảnh dao động; bị cuốn vào một chuyển thì không thể tự phá nổi.","congNang":["Trận pháp dựa vào tâm cảnh: tâm bất động thì phá được, tâm dao động thì bị cuốn không thoát","Khống chế tâm thần người bị nhốt, cứ chín nhịp thở tăng tốc một chuyển, tổng cộng chín chuyển @c1642","Tâm động dẫn tới tốc độ xoay tăng, hao tổn tâm thần liên tục, cuối cùng tiêu tốn thọ nguyên dẫn tới tử vong @c1642","Dùng Ngũ Hành tinh xoay tròn tạo ảo cảnh tác động qua thần thức, nhắm mắt vẫn thấy @c1642"],"trangThai":"Đang kích hoạt tại Ngũ Hành tinh","capNhatToi":"@c1641","tabs":{"tienTrinh":[{"chuong":"@c1641","loai":"xuat-hien","importance":"major","giaiDoan":"Kích hoạt sau khi Ngũ Hành đại trận bị phá","text":"Sau khi Vương Lâm phá xong toàn bộ Ngũ Hành đại trận, Cửu Chuyển Tâm Luân kích hoạt khiến Ngũ Hành tinh bắt đầu chuyển động. Đệ Cửu lão tổ giải thích nguyên lý: mỗi chín nhịp thở là một chuyển, tâm động càng nhanh thì chuyển càng nhanh, tất cả dựa vào tâm bất động.","anchor":"Cửu Chuyển Tâm Luân, mỗi chín nhịp thở là một chuyển, tâm động càng nhanh thì chuyển động càng nhanh"},{"chuong":"@c1642","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Hé lộ toàn bộ cơ chế chín chuyển và bị Vương Lâm bước đầu phá giải","text":"Lão già kim bào giải thích cơ chế chín chuyển cho Nạp Đa. Vương Lâm trải qua đệ nhất tới đệ cửu chuyển, tâm thần hao tổn cực độ, phun máu. Tại đệ cửu chuyển ngộ ra bản chất tâm động, tĩnh tâm lại, chuyển động bắt đầu chậm.","anchor":"Cửu Chuyển Tâm Luân, dù là trên Tiên Cương đại lục cũng rất ít người có thể phá vỡ"}]},"nguon":["@c1641","@c1642"]},{"id":"ngu-hanh-moc-tran","name":"Ngũ Hành mộc trận","cn":"五行木陣","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Một phần của Ngũ Hành Quy Nhất trận","hePhai":"Quy Nhất tông","soHuu":["Quy Nhất tông"],"blurb":"Trận thứ tư trong Ngũ Hành đại trận. Thiên địa cây cối rậm rạp, lá cây tấn công bao vây, mộc linh hóa khuôn mặt khổng lồ trên mặt đất.","detail":"Ngũ Hành mộc trận là trận thứ tư trong hệ thống Ngũ Hành đại trận của Quy Nhất tông. Bên trong là thiên địa cây cối rậm rạp, đại thụ vươn tận trời, lá cây có sợi tơ liên kết tấn công từ bốn phương bao vây. Cây cối mất lá có thể biến hóa thành khuôn mặt khổng lồ trên mặt đất — đó là mộc linh. Mộc chủ nhu hòa, cho phép đối phương chọn lựa thần phục hoặc bị hủy diệt. Bị Vương Lâm dùng thuật Tê Thiên xé thiên địa làm đôi rồi ép mộc linh quy phục.","nguon":["@c1641"]},{"id":"ngu-hanh-kim-tran","name":"Ngũ Hành kim trận","cn":"五行金陣","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Một phần của Ngũ Hành Quy Nhất trận","hePhai":"Quy Nhất tông","soHuu":["Quy Nhất tông"],"blurb":"Trận cuối cùng trong Ngũ Hành đại trận. Thiên địa toàn kiếm phát kim quang, vạn kiếm đồng reo lao tới tấn công, kim cứng rắn bất hủ tuyệt không khom mình.","detail":"Ngũ Hành kim trận là trận thứ năm và cuối cùng trong hệ thống Ngũ Hành đại trận. Bên trong thiên địa toàn kiếm phát kim quang thay thế mặt đất và bầu trời, sát khí bùng lên, vạn kiếm đồng loạt reo vang lao về phía kẻ xâm nhập. Kim cứng rắn bất hủ, một đường thẳng tiến tuyệt đối không khom mình. Sau khi kim trận bị Vương Lâm phá, toàn bộ Ngũ Hành đại trận tan rã hoàn toàn.","nguon":["@c1641"]},{"id":"than-tinh-dan-tam","name":"Thân tình dẫn tâm","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Phương pháp Vương Lâm tự sáng tạo để phá Cửu Chuyển Tâm Luân: không trực tiếp tĩnh tâm mà dùng thân thể dễ tĩnh hơn làm gốc, rồi từ thân → hồn → thần → tâm lần lượt tĩnh.","detail":"Trong lúc đối mặt đệ cửu chuyển của Cửu Chuyển Tâm Luân — tầng trận pháp tác động tâm thần mãnh liệt nhất — Vương Lâm nhận ra rằng tâm bị trận pháp quấy nhiễu quá sâu, không thể trực tiếp tĩnh lại được. Ông ngộ ra nguyên lý: thân thể là thứ dễ tĩnh nhất trong bốn yếu tố thân – hồn – thần – tâm. Khi thân tĩnh, ảnh hưởng lan sang hồn phách khiến hồn phách tĩnh; hồn phách tĩnh rồi kiềm chế được thần; ba thứ đều tĩnh thì tâm tất yếu cũng tĩnh theo. Phương pháp này không đối kháng trực diện mà đi đường vòng, lấy cái dễ kiểm soát dẫn dắt cái khó kiểm soát. Huyền La Đại Thiên Tôn đã phân tích rõ nguyên lý của phương pháp và đánh giá rất cao sự tự ngộ này của Vương Lâm.","thuocTinh":"Tâm pháp phá trận","nguonGoc":"Vương Lâm tự ngộ trong đệ cửu chuyển Cửu Chuyển Tâm Luân","dacDiem":"Lấy thân thể dễ tĩnh làm gốc dẫn động, lấy hồn phách làm trung gian kiềm chế tâm thần; không đối kháng trực diện mà đi đường vòng từ thân đến tâm","congNang":["Phá trận pháp tác động tâm thần bằng cách tĩnh tâm gián tiếp qua thân-hồn-thần"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1643","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1643","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm sáng tạo và sử dụng lần đầu","text":"Vương Lâm ngộ ra phương pháp thân tình dẫn tâm trong đệ cửu chuyển Cửu Chuyển Tâm Luân, dùng chín nhịp thở phá hoàn toàn trận pháp. Huyền La Đại Thiên Tôn quan sát và phân tích chính xác nguyên lý.","anchor":"lấy thân dẫn động, lấy thân rời xa đi. Thân là hình, tĩnh dễ dàng hơn"}]},"nguon":["@c1643"],"uyLuc":"Phá thành công đệ cửu chuyển Cửu Chuyển Tâm Luân chỉ trong chín nhịp thở @c1643"},{"id":"nghich-chuyen-cuu-chuyen-tam-luan","name":"Nghịch chuyển Cửu Chuyển Tâm Luân","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Nghịch chuyển Cửu Chuyển Tâm Luân là biến thể do Vương Lâm thi triển bằng cách lợi dụng nguyên lý cốt lõi của Cửu Chuyển Tâm Luân — tâm động thì tinh động — để đảo ngược trận pháp, đánh ngược vào chính phía bày trận. Tại chương @c1643, chiêu thức này khiến đa số tu sĩ Quy Nhất tông hôn mê ngay ở đệ tứ chuyển.","detail":"Sau khi phá giải Cửu Chuyển Tâm Luân, Vương Lâm không rời khỏi trận mà nắm bắt nguyên lý cốt lõi của trận pháp: tâm động thì tinh động. Hắn chủ ý nghịch động tâm, vẽ vòng tròn ngược chiều kim đồng hồ khiến Ngũ Hành tinh nghịch chuyển, từ đó đảo ngược toàn bộ uy lực Cửu Chuyển Tâm Luân hướng vào tu sĩ đứng trên Ngũ Hành tinh — tức chính những người bày trận thuộc Quy Nhất tông. Đây là ứng dụng chiến đấu thể hiện sự thấu hiểu trận pháp của Vương Lâm, biến vũ khí của đối phương thành công cụ phản kích.","congNang":["Nghịch chuyển Ngũ Hành tinh bằng cách vẽ vòng tròn ngược chiều kim đồng hồ, đảo ngược toàn bộ trận pháp Cửu Chuyển Tâm Luân đánh vào chính phía bày trận @c1643","Khiến đa số tu sĩ Quy Nhất tông hôn mê ở đệ tứ chuyển @c1643"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1643","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1643","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu sử dụng","text":"Vương Lâm nghịch chuyển Cửu Chuyển Tâm Luân đánh ngược tu sĩ Quy Nhất tông, khiến đa số hôn mê ở đệ tứ chuyển, lão già kim bào chống tới đệ thất chuyển.","anchor":"Tâm động thì tinh động. Giờ phút này tâm ta nghịch động, dẫn chuyển tu chân tinh này nghịch chuyển"}]},"nguon":["@c1643"],"uyLuc":"Đảo ngược Cửu Chuyển Tâm Luân khiến đa số tu sĩ Quy Nhất tông hôn mê chỉ ở đệ tứ chuyển @c1643","dacDiem":"Dựa trên nguyên lý tâm động thì tinh động, chủ ý nghịch động tâm để nghịch chuyển Ngũ Hành tinh, biến trận pháp của đối phương thành vũ khí phản kích ngược lại chính người bày trận"},{"id":"luc-hoa-an","name":"Lục Hoa Ấn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Quy Nhất tông","soHuu":["Vân Dật Phong"],"blurb":"Ấn quyết triệu sáu đóa hoa khổng lồ màu đen, từ mỗi đóa hoa thò ra một cánh tay trắng muốt đánh ra. Lực hủy diệt cực mạnh, khi vỡ tán để lại tà khí khắc lên cơ thể đối thủ gây rữa nát chảy mủ.","detail":"Vân Dật Phong bắt quyết điểm ra một ấn, triệu sáu đóa hoa khổng lồ màu đen tỏa u quang. Từ mỗi đóa hoa thò ra một cánh tay trắng muốt đánh ra, va chạm ngang sức với quyền của Vương Lâm cảnh Đạo Hư. Khi sáu đóa hoa vỡ tán, để lại sáu đóa hoa đen khắc trên cánh tay đối thủ gây rữa nát chảy mủ — cần Đạo Cổ bất diệt thể hoặc đan dược đặc biệt mới hóa giải.","congNang":["Triệu 6 đóa hoa đen khổng lồ + 6 cánh tay trắng muốt tấn công","Tà khí hoa đen khắc lên cơ thể đối thủ gây rữa nát chảy mủ"],"tabs":{"tienTrinh":[{"chuong":"@c1644","loai":"thi triển","importance":"normal","giaiDoan":"Vân Dật Phong thi triển lần đầu","text":"Vân Dật Phong dùng Lục Hoa Ấn giao chiến ngang sức Vương Lâm, sáu đóa hoa đen khắc lên cánh tay phải Vương Lâm gây rữa nát.","anchor":"sáu đóa hoa khổng lồ màu đen. Sáu đóa hoa này lập tức tỏa ra u quang"}]},"nguon":["@c1644"]},{"id":"dao-co-bat-diet-the","name":"Đạo Cổ bất diệt thể","cn":"","loai":"luyen-the","loaiLabel":"Luyện thể","phamCap":"Không rõ","hePhai":"Đạo cổ nhất mạch","soHuu":["Vương Lâm"],"blurb":"Thể chất đặc biệt thuộc Đạo Cổ nhất mạch, có lực lượng khôi phục cực mạnh, có thể tự hóa giải tà thuật và thương tổn ngoại lai.","detail":"Đạo Cổ bất diệt thể cho phép Vương Lâm tự động khôi phục thương tổn ngoại lai. Tại Ngũ Hành tinh, sáu đóa hoa đen từ Lục Hoa Ấn của Vân Dật Phong khắc lên cánh tay phải gây rữa nát — dưới lực lượng khôi phục của bất diệt thể liền tan nát, tốc độ nhanh hơn so với dùng đan dược vài nhịp thở.","congNang":["Tự hóa giải tà thuật và thương tổn ngoại lai trên cơ thể","Tốc độ khôi phục nhanh hơn đan dược đặc biệt"],"tabs":{"tienTrinh":[{"chuong":"@c1644","loai":"thi triển","importance":"normal","giaiDoan":"Khôi phục nhanh hơn đan dược","text":"Vương Lâm dùng bất diệt thể đánh tan sáu đóa hoa đen trên cánh tay phải, khôi phục nhanh hơn Vân Dật Phong dùng đan dược vài nhịp thở.","anchor":"dưới lực lượng khôi phục của Đạo cổ bất diệt thể của Vương Lâm liền tan nát"}]},"nguon":["@c1644"]},{"id":"mat-quy-nhap-huyen","name":"Mặt quỷ nhập huyễn, mộng ảo ngàn năm","aliases":["Mặt quỷ nhập huyễn"],"loai":"than-thong","loaiLabel":"Thần thông","hePhai":"Mộng ảo","soHuu":["Vương Lâm"],"blurb":"Thần thông mộng ảo do Vương Lâm thi triển, sử dụng tấm buồm mặt quỷ (Cấm Phiên) làm môi giới, kết hợp tiếp xúc mi tâm đối tượng và niệm chú để đưa thần thức vào thế giới mộng ảo tái hiện ký ức quá khứ. Lần thi triển được ghi nhận là khi Vương Lâm cùng Lý Mộ Uyển nhập mộng, tái hiện cảnh tượng lần gặp gỡ đầu tiên hơn hai ngàn năm trước ở hải ngoại.","detail":"Khi thi triển, Vương Lâm đặt tay phải lên mi tâm mình, tay trái lên mi tâm Lý Mộ Uyển, rồi niệm chú kích hoạt. Tấm buồm mặt quỷ (Cấm Phiên) lập tức biến ảo, mặt quỷ trên buồm gào thét vô thanh rồi lao vào mi tâm Vương Lâm, sương mù dày đặc bao phủ toàn thân hai người. Thần thông này tạo ra một thế giới mộng ảo có khả năng tái hiện cảnh tượng quá khứ với độ chân thực cao. Trong lần thi triển duy nhất được ghi nhận, Vương Lâm đã dùng nó để cùng Lý Mộ Uyển sống lại cảnh gặp gỡ đầu tiên ở hải ngoại hơn hai ngàn năm trước. Điều kiện thi triển bắt buộc gồm: tấm buồm mặt quỷ làm môi giới, tiếp xúc mi tâm đối tượng, và niệm chú kích hoạt.","thuocTinh":"Mộng ảo / Ký ức","dacDiem":"Cần tấm buồm mặt quỷ (Cấm Phiên) làm môi giới, tiếp xúc mi tâm đối tượng, niệm chú kích hoạt. Khi kích hoạt, mặt quỷ trên buồm gào thét vô thanh lao vào mi tâm người thi triển, sương mù dày đặc bao phủ toàn thân.","congNang":["Đưa thần thức của người thi triển và đối tượng vào thế giới mộng ảo, tái hiện cảnh tượng ký ức quá khứ với độ chân thực cao @c1648"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1648","trangThai":"thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1648","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Vương Lâm thi triển lần đầu, dùng tấm buồm mặt quỷ kết hợp tiếp xúc mi tâm Lý Mộ Uyển để nhập mộng ảo tái hiện lần gặp gỡ đầu tiên hơn hai ngàn năm trước.","anchor":"Mặt quỷ nhập huyễn, mộng ảo ngàn năm"}]},"nguon":["@c1648"]},{"id":"tam-hon-that-phach","name":"Tam hồn thất phách","cn":"三魂七魄","loai":"khac","loaiLabel":"Hệ thống","phamCap":"Không rõ","hePhai":"Thất Thải Tiên Tôn","soHuu":["Thất Thải Tiên Tôn"],"blurb":"Tam hồn thất phách là hệ thống hồn phách của Thất Thải Tiên Tôn, trong đó mỗi hồn phách chuyển thế qua luân hồi thành một nhân vật riêng biệt. Bốn trong bảy phách đã xảy ra biến số thiên đạo, trở thành thân thể độc lập hoàn toàn tách biệt khỏi bản thể.","detail":"Tam hồn thất phách thuộc về Thất Thải Tiên Tôn. Bảy phách lần lượt chuyển thế thành các nhân vật: Thanh Thủy, Tư Đồ Nam, Tham Lang, Thanh Lâm, Mộc Băng Mi, Tán Linh thượng nhân, và phách thứ bảy đã bị Thiên Vận Tử nuốt mất nhưng không còn tồn tại trong thiên đạo hiện tại. Hồn thứ ba là Tạ Thanh. Bốn phách — Tham Lang, Thanh Lâm, Mộc Băng Mi, Tán Linh — đã trải qua nhiều lần luân hồi, trong quá trình đó xảy ra biến số thiên đạo, khiến chúng trở thành thân thể chính thức, hoàn toàn tách biệt khỏi Thất Thải Tiên Tôn. Hai phách còn lại — Thanh Thủy và Tư Đồ Nam — chưa xảy ra biến số nên chưa hoàn toàn độc lập. Tại chương @c1653, Vương Lâm được Huyền La điểm chỉ, nhận ra bản chất biến số khiến bốn phách trở thành thân thể độc lập. Nếu nắm được lực lượng biến số trong thiên đạo, có thể khiến hồn","congNang":["Mỗi hồn phách chuyển thế thành nhân vật riêng biệt qua luân hồi","Biến số thiên đạo trong quá trình luân hồi có thể biến phách thành thân thể độc lập, hoàn toàn tách biệt khỏi bản thể @c1653","Nếu nắm được lực lượng biến số trong thiên đạo, có thể khiến hồn thứ ba độc lập và ngăn tam hồn dung hợp"],"tabs":{"tienTrinh":[{"chuong":"@c1653","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Giác ngộ biến số thiên đạo","text":"Vương Lâm được Huyền La điểm chỉ, nhận ra bốn phách đã qua luân hồi xảy ra biến số trở thành thân thể độc lập. Xác nhận hồn thứ ba là Tạ Thanh. Phách thứ bảy không còn trong thiên đạo.","anchor":"bốn người bọn họ trở thành thân thể chính thức, hoàn toàn không giống với Thất Thải Tiên Tôn"}]},"nguon":["@c1653"]},{"id":"khong-diet-khi","name":"Không Diệt khí","cn":"不灭气","loai":"than-thong","loaiLabel":"Thần thông / Khí tức","phamCap":"Không rõ (vượt tầm hiểu biết Đại Thiên Tôn)","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Không Diệt khí là khí tức sơ hiện khi Vương Lâm cực độ phẫn nộ thề diệt trời, toàn thân bộc phát khí thế ngưng tụ thành thanh kiếm hư ảo mang uy lực phá thiên không. Huyền La Đại Thiên Tôn lần đầu đại biến sắc mặt, vô cùng khiếp sợ trước khí tức này, thừa nhận nó vượt ngoài tầm hiểu biết của mình.","detail":"Không Diệt khí sinh ra từ lời thề của Vương Lâm khi cực độ phẫn nộ — thề cả đời muốn diệt trời. Lời thề huyễn hóa thành khí tức Không Diệt, ngưng tụ thành thanh kiếm hư ảo có khí tức như muốn phá tan thiên không. Huyền La Đại Thiên Tôn lần đầu đại biến sắc mặt, vô cùng khiếp sợ trước khí tức này, cho thấy bản chất của nó vượt tầm hiểu biết ngay cả đối với cường giả cấp Đại Thiên Tôn.","congNang":["Bộc phát thành thanh kiếm hư ảo có khí tức phá thiên không @c1654"],"dacDiem":"Sinh ra từ lời thề cực độ phẫn nộ, vượt tầm hiểu biết của Đại Thiên Tôn","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1654","tangDatToi":"Sơ hiện","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1654","loai":"xuat-hien","importance":"major","giaiDoan":"Sơ hiện","text":"Vương Lâm phẫn nộ thề diệt trời, toàn thân bộc phát khí thế ngưng tụ thành thanh kiếm hư ảo mang khí tức Không Diệt. Huyền La Đại Thiên Tôn kinh hãi nhận ra, cho rằng lời thề đã huyễn hóa ra khí tức này.","anchor":"Lời thề của người này không ngờ lại có thể huyễn hóa ra khí tức của Không Diệt"}]},"nguon":["@c1654"],"uyLuc":"Khiến Huyền La Đại Thiên Tôn lần đầu đại biến sắc mặt, vô cùng khiếp sợ, thừa nhận vượt ngoài tầm hiểu biết của mình."},{"id":"ba-dao-phong-an-ta-thanh","name":"Ba đạo phong ấn của Tạ Thanh","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật / Phong ấn","phamCap":"Không rõ","hePhai":"","soHuu":["Tạ Thanh"],"blurb":"Ba đạo phong ấn do Tạ Thanh dùng hồn tu lực tích lũy nhiều năm ngưng tụ mà thành, bố trí nhằm phục vụ kế hoạch giúp Vương Lâm thu phục ba hồn. Phong ấn thứ nhất tự kích hoạt khi Tạ Thanh chết để chặn luân hồi hồn thứ ba, hai phong ấn còn lại phối hợp lực lượng Tiên Cương đại lục phong ấn hồn thứ nhất và hồn thứ hai.","detail":"Ba đạo phong ấn là kết tinh toàn bộ hồn tu lực mà Tạ Thanh ngưng tụ qua nhiều năm, mang tính chất hy sinh cực lớn khiến tâm hồn hao tổn cực độ. Phong ấn thứ nhất do tự thân Tạ Thanh dẫn động, kích hoạt vào thời điểm Tạ Thanh tử vong, ngăn hồn thứ ba đi vào luân hồi để Vương Lâm có thể thu lấy. Khi hồn thứ ba thức tỉnh hoàn toàn sẽ kích hoạt mở trung tâm động phủ và đại môn thông ra Tiên Cương đại lục, rời khỏi động phủ giới. Hai đạo phong ấn còn lại phối hợp với lực lượng từ Tiên Cương đại lục khi đại môn mở ra, giúp Vương Lâm phong ấn hồn thứ nhất và hồn thứ hai. Toàn bộ ba đạo phong ấn là một bố cục liên hoàn mà Tạ Thanh sắp đặt trước khi chết, mỗi phong ấn kích hoạt tuần tự phục vụ cho mục tiêu cuối cùng. @c1654","congNang":["Chặn luân hồi hồn thứ ba khi Tạ Thanh chết, để Vương Lâm thu lấy @c1654","Mở trung tâm động phủ và đại môn thông Tiên Cương đại lục khi hồn thứ ba thức tỉnh hoàn toàn @c1654","Phối hợp lực lượng từ Tiên Cương đại lục phong ấn hồn thứ nhất và hồn thứ hai @c1654"],"nguoiTu":[{"ten":"Tạ Thanh","tuChuong":"@c1654","tangDatToi":"Hoàn thành","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1654","loai":"thi-trien","importance":"major","giaiDoan":"Hoàn thành và kích hoạt","text":"Tạ Thanh dùng hồn tu lực nhiều năm ngưng tụ ba đạo phong ấn. Phong ấn thứ nhất tự thân dẫn động khi chết. Tạ Thanh khí tuyệt thân vong, phong ấn kích hoạt — hồn thứ ba không luân hồi, Vương Lâm thu lấy.","anchor":"Những năm gần đây, sau khi hồn thứ ba thức tỉnh, ta lấy hồn tu lực, ngưng tụ ba đạo phong ấn"}]},"nguon":["@c1654"],"uyLuc":"Tạ Thanh tâm hồn hao tổn cực độ vì ngưng tụ ba đạo phong ấn, cho thấy mức hồn tu lực tiêu hao vô cùng lớn, đủ sức can thiệp luân hồi và liên thông hai giới.","dacDiem":"Phong ấn liên hoàn ba đạo, mỗi đạo kích hoạt tuần tự theo điều kiện khác nhau; do hồn tu lực nhiều năm ngưng tụ, phong ấn thứ nhất tự thân dẫn động không cần thi triển thêm."},{"id":"dinh-quy-tac-tan-gioi","name":"Định quy tắc tàn giới","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Năng lực đặc biệt cho phép truyền thần niệm để định ra quy tắc cho tàn giới loại ba (không sinh linh), đòi hỏi huyết mạch tiên nhân.","detail":"Vương Lâm thử truyền thần niệm vào ngọn núi trọc trong tàn giới loại ba để định quy tắc. Thiên địa ầm vang, tinh vực vặn vẹo kịch liệt, quy tắc mơ hồ sinh ra nhưng bị đè nén vì tàn giới không đủ lực ngưng tụ. Điều kiện tiên quyết là cần huyết mạch tiên nhân.","thuocTinh":"Quy tắc","nguonGoc":"Năng lực vốn có của tàn giới loại ba, người đầu tiên tới có thể định quy tắc","yeuCau":"Huyết mạch tiên nhân, tàn giới đủ lực lượng","congNang":["Thay đổi pháp tắc trong tàn giới loại ba (không sinh linh)"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1658","tangDatToi":"","trangThai":"thử nghiệm thất bại lần đầu"}],"tabs":{"tienTrinh":[{"chuong":"@c1658","loai":"thi triển","importance":"normal","giaiDoan":"Thử nghiệm lần đầu","text":"Vương Lâm truyền thần niệm vào ngọn núi trọc trên tu chân tinh thứ năm, thiên địa ầm vang, quy tắc mơ hồ sinh ra nhưng bị đè nén vì tàn giới không đủ lực ngưng tụ.","anchor":"cấm chế quy tắc này đều phải cần tới huyết mạch tiên nhân"}]},"nguon":["@c1658"]},{"id":"quy-tac-cam-phi-hanh","name":"Quy tắc cấm phi hành","cn":null,"loai":"bi-thuat","loaiLabel":"Quy tắc tàn giới","phamCap":"Quy tắc duy nhất ngưng tụ hoàn chỉnh trong tàn giới","hePhai":null,"soHuu":["Vương Lâm"],"blurb":"Quy tắc do Vương Lâm thiết lập trong tàn giới, khiến đối phương mất năng lực phi hành và rơi xuống nhanh.","detail":"Quy tắc duy nhất mà Vương Lâm có thể ngưng tụ hoàn chỉnh trong tàn giới của mình. Hiệu quả khiến mọi kẻ bước vào tàn giới mất năng lực phi hành, phải rơi xuống. Tuy nhiên có giới hạn thời gian tùy theo tu vi đối phương — tu vi càng cao thì thời gian bị ảnh hưởng càng ngắn. Ngoài ra quy tắc này không ảnh hưởng tới pháp bảo, đối phương vẫn có thể dùng pháp bảo nâng thân. Trận pháp cấm chế đi kèm chỉ đủ sức giết được ba người, sau đó mất hiệu lực sát thương. Vương Lâm dùng quy tắc này phục kích giết tổng cộng bốn đệ tử Thất Đạo Tông: lão già viễn cổ tiên nhân ngày đầu bị mất phi hành rồi bị huyết kiếm xuyên mi tâm; ba tiên nhân ngày thứ sáu (một Không Niết sơ kỳ, hai thiên nhân ngũ suy) cũng bị cấm phi hành rồi bị giết trong chưa tới ba nhịp thở.","nguon":["@c1659"]},{"id":"phong-an-chin-chi","name":"Phong ấn chín chỉ","cn":"","loai":"bi-thuat","loaiLabel":"Cấm chế","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Phong ấn chín chỉ là cấm chế phong ấn mà Vương Lâm sử dụng bằng cách điểm liên tiếp chín chỉ lên người đối phương, mỗi chỉ đưa vào một luồng lực lượng phong ấn, tạo thành mạng cấm chế hư ảo bao phủ toàn thân, đạt phong ấn đại thành. Pháp thuật này được dùng kết hợp sau Định thân thuật để hoàn toàn khống chế mục tiêu.","detail":"Phong ấn chín chỉ là thuật cấm chế phong ấn cực mạnh. Khi thi triển, Vương Lâm điểm chín chỉ liên tiếp lên thân thể đối phương, mỗi chỉ mang theo một luồng lực lượng phong ấn. Chín luồng lực lượng này hội tụ tạo thành mạng cấm chế hư ảo tựa mạng nhện tràn ngập toàn thân mục tiêu, đạt tới trạng thái phong ấn đại thành. Thuật này được sử dụng sau khi đối phương đã bị Định thân thuật cố định, nhằm hoàn toàn khống chế đối thủ. Tại @c1661, Vương Lâm thi triển Phong ấn chín chỉ lên người Tử Hà, đạt phong ấn đại thành rồi thu nàng vào tay áo.","congNang":["Phong ấn hoàn toàn đối phương sau khi đã bị Định thân thuật cố định, tạo cấm chế hư ảo bao phủ toàn thân mục tiêu @c1661"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1661","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1661","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Vương Lâm điểm chín chỉ lên người Tử Hà tạo cấm chế phong ấn đại thành, thu nàng vào tay áo.","anchor":"Chín chỉ này điểm xuống, phong ấn đại thành!"}]},"nguon":["@c1661"],"uyLuc":"Chín chỉ điểm xong đạt phong ấn đại thành, mạng cấm chế hư ảo tràn ngập toàn thân đối phương, khống chế hoàn toàn khiến đối thủ bị thu gọn vào tay áo @c1661","dacDiem":"Thi triển bằng chín chỉ liên tiếp, mỗi chỉ đưa vào một luồng lực lượng phong ấn riêng biệt, chín luồng hội tụ tạo thành mạng cấm chế hư ảo tựa mạng nhện bao trùm toàn thân đối phương"},{"id":"quy-tac-tan-gioi-bach-ho","name":"Quy tắc tàn giới (Bạch Hổ chiến tướng)","cn":"","loai":"khac","loaiLabel":"Quy tắc","phamCap":"","hePhai":"","soHuu":["Bạch Hổ"],"blurb":"Quy tắc tàn giới là hệ thống luật lệ do Bạch Hổ chiến tướng — người đầu tiên bước vào tàn giới — đơn phương thiết lập, ràng buộc mọi người đến sau phải tuân theo.","detail":"Trong tàn giới, ai vào trước sẽ nắm quyền định ra toàn bộ quy tắc; những người đến sau đều bị ràng buộc không thể vi phạm. Bạch Hổ chiến tướng lợi dụng cơ chế này thiết lập quy tắc khiến người vào phải hư ảo hóa bản thân và liên kết với binh tướng thế tục để chiến đấu. Theo thông tin trong tiến trình, chỉ đạo nhân bảy màu (Thất Thải Tiên Tôn) hoặc Chiến lão quỷ mới có thể thoát khỏi sự ràng buộc này. Vương Lâm chọn đứng yên không bước vào để giữ mình ngoài phạm vi quy tắc.","congNang":["Ràng buộc mọi người đến sau vào quy tắc do người đến trước đặt ra @c1661","Hư ảo hóa và liên kết với binh tướng thế tục @c1661"],"tabs":{"tienTrinh":[{"chuong":"@c1661","loai":"xuất hiện","importance":"major","giaiDoan":"Bạch Hổ thiết lập","text":"Bạch Hổ chiến tướng là người đầu tiên vào tàn giới, đã thiết lập toàn bộ quy tắc, tự tin chỉ đạo nhân bảy màu hoặc Chiến lão quỷ mới thoát.","anchor":"tất cả các quy tắc ở đây đều do ta định ra!"}]},"nguon":["@c1661"],"dacDiem":"Người vào tàn giới đầu tiên nắm toàn quyền lập pháp; chỉ đạo nhân bảy màu hoặc Chiến lão quỷ mới thoát khỏi ràng buộc."},{"id":"that-thai-dao-lien","name":"Thất Thải Đạo Liên","cn":"七彩道莲","aliases":["đài sen bảy màu"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Đạo nhân bảy màu"],"blurb":"Thần thông của Đạo nhân bảy màu, triệu hoa sen bảy cánh bảy màu có thể co rút thành nụ hoa phòng ngự hoặc nở cánh phản công, từng chịu được đường đao mượn quy tắc cả một giới nhưng mất hai cánh.","detail":"Đạo nhân bảy màu thi triển Thất Thải Đạo Liên bằng cách triệu hoa sen bảy cánh bảy màu, hô khẩu quyết khiến hoa co rút thành nụ bao phủ toàn thân để phòng ngự, hoặc nở cánh phóng ra tấn công đối thủ. Trong trận chiến với Vương Lâm, hoa sen ở trạng thái nụ đã chịu được đường đao mượn lực lượng quy tắc cả một giới, song bị vỡ mất hai cánh; năm cánh còn lại nở ra chuyển sang phản công (@c1664).","congNang":["Phòng ngự: co rút thành nụ hoa bao phủ toàn thân, chịu đòn cực mạnh @c1664","Phản công: nở cánh phóng ra tấn công đối thủ @c1664"],"uyLuc":"Chịu được đường đao mượn quy tắc cả một giới nhưng mất hai cánh","dacDiem":"Bảy cánh bảy màu, có khẩu quyết khai/hợp","nguoiTu":[{"ten":"Đạo nhân bảy màu","tuChuong":"@c1664","tangDatToi":"Không rõ","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1664","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Đạo nhân bảy màu triệu Thất Thải Đạo Liên phòng ngự đường đao mượn lực cả giới của Vương Lâm, bị vỡ hai cánh hoa. Sau đó nở năm cánh còn lại phản công.","anchor":"Thất thải đạo liên, liên ngưng binh tu"}]},"nguon":["@c1664"]},{"id":"that-thai-dao-thuong","name":"Thất Thải Đạo Thương","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông ngưng tụ ánh sáng bảy màu thành thanh trường thương khí tức kinh thiên, giống hệt thần thông của đạo nhân bảy màu.","detail":"Vương Lâm thi triển ánh sáng bảy màu ngưng tụ thành thanh trường thương bảy màu tỏa khí tức kinh thiên, cắm xuống mặt đất làm tầng mai phục thứ hai. Hình thức giống hệt thần thông của đạo nhân bảy màu.","congNang":["Ngưng tụ ánh sáng bảy màu thành trường thương khí tức kinh thiên"],"dacDiem":"Giống hệt thần thông của đạo nhân bảy màu","tabs":{"tienTrinh":[{"chuong":"@c1666","loai":"thi triển","importance":"normal","giaiDoan":"Vương Lâm dùng làm tầng mai phục thứ hai","text":"Vương Lâm thi triển ánh sáng bảy màu ngưng tụ thành trường thương bảy màu cắm xuống mặt đất trước mặt, tạo tầng mai phục thứ hai trên tu chân tinh.","anchor":"Ánh sáng bảy màu này nhìn lại giống hệt thần thông của đạo nhân bảy màu"}]},"nguon":["@c1666"]},{"id":"quy-kiem-huyet-pham","name":"Quỷ Kiếm Huyết Phàm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Quỷ Kiếm Huyết Phàm là ảo thuật hoặc thần thông đóng vai trò đệ tứ phục trong phục sát trận của Vương Lâm, tạo đám sương mù đỏ như máu hóa thành mặt quỷ khổng lồ nuốt lấy đối phương khiến mục tiêu lập tức mê man bất động.","detail":"Quỷ Kiếm Huyết Phàm là đệ tứ phục trong phục sát trận do Vương Lâm bày ra. Khi thi triển, một đám sương mù đỏ như máu hiện ra rồi hóa thành mặt quỷ khổng lồ nuốt trọn mục tiêu, khiến đối phương ngay lập tức mê man khoanh chân ngồi xuống, hoàn toàn mất khả năng cử động. Chiến lão quỷ bị trúng chiêu không thể thoát được; đạo nhân bảy màu cũng từng bị vây khốn trong thời gian ngắn.","congNang":["Sương mù đỏ hóa thành mặt quỷ khổng lồ nuốt lấy đối phương, khiến mục tiêu lập tức mê man bất động @c1668","Có thể vây khốn cường giả trong thời gian ngắn"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1668","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1668","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Vương Lâm tung đệ tứ phục, sương mù đỏ hóa mặt quỷ nuốt Chiến lão quỷ khiến hắn mê man bất động.","anchor":"ở phía trước Chiến lão quỷ xuất hiện một đám sương mù đỏ như máu"}]},"nguon":["@c1668"],"uyLuc":"Chiến lão quỷ bị nuốt vào trong mặt quỷ, lập tức mê man khoanh chân ngồi không cử động, hoàn toàn không thoát được @c1668","dacDiem":"Biểu hiện dưới dạng đám sương mù đỏ như máu ngưng tụ thành mặt quỷ khổng lồ, thiên về khống chế — khiến đối phương mất ý thức và bất động thay vì gây sát thương trực tiếp"},{"id":"mat-thuat-bach-ho","name":"Mật thuật Bạch Hổ","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Bạch Hổ","soHuu":["Vương Lâm"],"blurb":"Mật thuật Bạch Hổ là bí thuật truyền lực chấn động sâu vào lòng đất, được Vương Lâm sử dụng trong phục sát trận để kích hoạt sinh vật đang ngủ say bên dưới.","detail":"Đệ lục phục trong phục sát trận của Vương Lâm. Khi thi triển, Vương Lâm vỗ tay lên mặt đất, kết hợp mật thuật Bạch Hổ cùng phương pháp thao túng lực lượng học được từ đệ nhị Chu Tước kí, truyền chấn động nhập sâu lòng đất nhằm kích thích Mục Ngư biến dị thức tỉnh.","congNang":["Truyền lực chấn động sâu vào lòng đất, kích hoạt sinh vật đang ngủ say bên dưới @c1668"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1668","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1668","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Vương Lâm vỗ tay lên mặt đất dùng mật thuật Bạch Hổ kết hợp phương pháp thao túng lực lượng đệ nhị Chu Tước kích thích Mục Ngư biến dị thức tỉnh.","anchor":"tay trái hắn vỗ lên mặt đất mật thuật của Bạch Hổ, phương pháp thao túng lực lượng mà hắn học được từ đệ nhị Chu Tước"}]},"nguon":["@c1668"]},{"id":"luc-bat-son-he","name":"Lục bạt sơn hề","cn":"力拔山兮","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Đạo nhân bảy màu"],"blurb":"Thần thông của đạo nhân bảy màu, triệu hoán cánh tay bảy màu khổng lồ từ không trung, có thể túm bắt và ném mãnh thú cỡ lớn.","detail":"Khi thi triển, hai tay bấm quyết, tay phải chỉ lên bầu trời, triệu hoán một cánh tay bảy màu khổng lồ từ trong màn u ám trên không. Cánh tay này có sức mạnh kinh khủng, túm lấy con Mục Ngư dài mấy ngàn trượng lôi ra khỏi lòng đất rồi ném xuống mặt đất đằng xa, khiến tu chân tinh nứt vỡ và Mục Ngư trọng thương.","congNang":["Triệu hoán cánh tay bảy màu khổng lồ từ không trung, túm bắt/ném mãnh thú cỡ lớn"],"nguoiTu":[{"ten":"Đạo nhân bảy màu","tuChuong":"@c1669","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1669","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Đạo nhân bảy màu thi triển Lục bạt sơn hề triệu hoán cánh tay bảy màu khổng lồ, túm lấy Mục Ngư thứ nhất lôi khỏi lòng đất ném xa khiến nó trọng thương, tu chân tinh nứt vỡ.","anchor":"hai tay bấm quyết, tay phải bỗng nhiên chỉ lên bầu trời. -Lục bạt sơn hề!"}]},"nguon":["@c1669"]},{"id":"thien-phu-than-thong-muc-ngu","name":"Thiên phú thần thông Mục Ngư (mở mắt biến hóa)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Mục Ngư"],"blurb":"Thiên phú thần thông của loài Mục Ngư, khi mở mắt có thể biến hóa thành bất kỳ vật gì và đạt được một phần uy lực của vật đó. Rất hiếm khi Mục Ngư mở mắt, được coi là kỳ tích hiếm thấy.","detail":"Mục Ngư là loài thú bình thường nhắm mắt, một khi mở hai mắt sẽ phát động thiên phú biến hóa, có thể biến thành bất kỳ vật gì và có được một phần uy lực của vật đó. Hiện tượng Mục Ngư mở mắt cực kỳ hiếm, là kỳ tích khó gặp. Huyền La Đại Thiên Tôn là người duy nhất biết đến thần thông này. Tám con Mục Ngư từng mở mắt biến hóa thành tám mũi tên giống y hệt mũi tên Lý Quảng cả hình dáng lẫn khí tức (@c1670).","congNang":["Mở mắt biến hóa thành bất kỳ vật gì, có được một phần uy lực của vật đó (@c1670)"],"dacDiem":"Rất hiếm khi Mục Ngư mở mắt, là kỳ tích hiếm thấy. Huyền La Đại Thiên Tôn là người duy nhất biết thần thông này.","tabs":{"tienTrinh":[{"chuong":"@c1670","loai":"thi triển","importance":"major","giaiDoan":"Tám con Mục Ngư mở mắt biến hóa","text":"Tám con Mục Ngư mở mắt phát động thiên phú biến hóa thành tám mũi tên Lý Quảng giống y hệt nguyên bản. Sau khi hào quang bảy màu sụp đổ, tám con quay về hình dạng gốc, đồng loạt hấp hối.","anchor":"loài thú Mục Ngư này một khi mở hai mắt thì có thể biến hóa thành bất cứ thứ gì, còn có được một phần uy lực của vật đó"}]},"nguon":["@c1670"],"uyLuc":"Tám con Mục Ngư mở mắt biến hóa thành tám mũi tên Lý Quảng giống y hệt nguyên bản cả hình dáng lẫn khí tức (@c1670)."},{"id":"chin-mat-troi-than-thong","name":"Chín mặt trời (thần thông đạo nhân bảy màu)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Đạo nhân bảy màu"],"blurb":"Chín mặt trời là thần thông mạnh nhất của đạo nhân bảy màu, triệu xuất chín mặt trời chói lọi bộc phát hào quang vạn trượng. Khi nổ tung, thần thông này tạo sức mạnh hủy diệt thiên địa, đủ sức phá hủy ba trăm tàn giới và giết Thanh Long chiến tướng.","detail":"Thần thông mạnh nhất của đạo nhân bảy màu. Khi thi triển, đạo nhân bảy màu bộc phát toàn bộ tu vi, xuất hiện chín mặt trời chói lọi bên ngoài thân thể, bộc phát hào quang vạn trượng. Tại chương @c1670, đạo nhân bảy màu thi triển chín mặt trời, dùng chúng va chạm với tiễn thứ ba. Khi nổ tung, thần thông tạo sức mạnh hủy diệt kinh thiên, đủ sức phá hủy ba trăm tàn giới và giết Thanh Long chiến tướng.","congNang":["Triệu xuất chín mặt trời chói lọi bên ngoài thân thể, bộc phát hào quang vạn trượng @c1670","Nổ tung tạo sức mạnh hủy diệt thiên địa, đủ sức phá hủy ba trăm tàn giới và giết Thanh Long chiến tướng","Va chạm đối kháng cường công (đối chọi tiễn thứ ba) @c1670"],"tabs":{"tienTrinh":[{"chuong":"@c1670","loai":"thi triển","importance":"major","giaiDoan":"Đạo nhân bảy màu thi triển chín mặt trời đối kháng tiễn thứ ba","text":"Đạo nhân bảy màu bộc phát toàn bộ tu vi thi triển chín mặt trời chói lọi. Chín mặt trời va chạm tiễn thứ ba của Vương Lâm nổ tung, tạo sức mạnh hủy diệt phá hủy ba trăm tàn giới, giết Thanh Long chiến tướng.","anchor":"Chín mặt trời này là thần thông mạnh nhất của đạo nhân bảy màu"}]},"nguon":["@c1670"],"uyLuc":"Khi nổ tung tạo sức mạnh hủy diệt kinh thiên, đủ sức phá hủy ba trăm tàn giới và giết Thanh Long chiến tướng.","dacDiem":"Cần bộc phát toàn bộ tu vi mới thi triển được, xuất hiện dưới dạng chín mặt trời chói lọi bao quanh thân thể."},{"id":"ngu-hoa-bat-mon","name":"Ngũ hoa bát môn","cn":"五花八門","loai":"bi-thuat","loaiLabel":"Trận pháp / Hệ thống phòng hộ","phamCap":"Không rõ","hePhai":"Thất Thải Tiên Tôn","soHuu":["Thất Thải Tiên Tôn"],"blurb":"Ngũ hoa bát môn là hệ thống phòng hộ nhiều tầng do Thất Thải Tiên Tôn tạo ra tại trung tâm động phủ, gồm năm đóa hoa và bát môn (bảy giả một thật), cửa thật thông tới Tiên Cương đại lục.","detail":"Công pháp trận thế này do Thất Thải Tiên Tôn thiết lập nhằm bảo vệ lối vào Tiên Cương đại lục. Kết cấu gồm năm đóa hoa xếp theo tầng: đệ nhất hoa là ba trăm tàn giới (đã sụp đổ), đệ nhị hoa là thế giới đóng băng tái hiện Đông Lâm tông, đệ ngũ hoa là phong ấn của Thất Thải Tiên Tôn đối với cánh cửa thông tới Tiên Cương đại lục. Bát môn ẩn trong đóa hoa cuối cùng, bảy giả một thật, chỉ cửa thật mới dẫn tới đích. Vương Lâm từng lần lượt vượt qua các tầng, bắt đầu từ ba trăm tàn giới rồi tiến vào thế giới đóng băng của đệ nhị hoa.","congNang":["Phòng hộ nhiều tầng bảo vệ lối vào Tiên Cương đại lục","Bát môn bảy giả một thật ngăn cản xâm nhập @c1671","Đệ nhất hoa dùng ba trăm tàn giới làm tầng chắn đầu tiên","Đệ nhị hoa tái hiện thế giới đóng băng (Đông Lâm tông) làm tầng chắn thứ hai @c1671","Đệ ngũ hoa phong ấn cánh cửa thông tới Tiên Cương đại lục"],"nguonGoc":"Do Thất Thải Tiên Tôn tạo ra","dacDiem":"Năm đóa hoa, bát môn bảy giả một thật","tabs":{"tienTrinh":[{"chuong":"@c1671","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Lộ cấu trúc toàn bộ hệ thống","text":"Vương Lâm sau khi rời ba trăm tàn giới (đệ nhất hoa đã sụp đổ) tiến vào đệ nhị hoa — thế giới đóng băng. Cấu trúc Ngũ hoa bát môn được hé lộ: năm đóa hoa, bát môn bảy giả một thật, cửa thật thông Tiên Cương đại lục, đệ ngũ hoa là phong ấn.","anchor":"Ngũ hoa bát môn, đây chính là tên của vòng phòng hộ trong trung tâm động phủ của Thất Thải Tiên Tôn"}]},"nguon":["@c1671"]},{"id":"tran-phap-dong-bang-dong-phu-gioi","name":"Trận pháp đóng băng (chủ nhân động phủ giới)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Đạo cổ nhất mạch","soHuu":["Vương Lâm"],"blurb":"Trận pháp trong động phủ giới Diệp Mịch, người đầu tiên tiến vào là chủ nhân, có thể kích hoạt biến thiên địa thành kết giới đóng băng phong bế mọi kẻ xâm nhập.","detail":"Nữ Cổ Thần giải thích người đầu tiên tiến vào nơi này là chủ nhân, có thể kích hoạt trận pháp biến toàn bộ thiên địa thành khối băng ngăn cản tất cả mọi người bước vào. Tuy nhiên, kẻ tu vi quá cao mang khí tức chủ nhân thì tầng băng không giữ được lâu.","congNang":["Phong bế toàn bộ thiên địa thành khối băng, phong ấn mọi kẻ xâm nhập"],"nguon":["@c1672"]},{"id":"dao-co-bat-diet-chi","name":"Đạo Cổ bất diệt chỉ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Đạo Cổ","soHuu":["Vương Lâm"],"blurb":"Thần thông ngưng tụ Đạo Cổ lực trên năm ngón tay, xuất hiện ngàn vạn tàn ảnh rồi hợp nhất chụp xuống, uy lực cực mạnh.","detail":"Vương Lâm thi triển: Đạo Cổ lực trong cơ thể ầm ầm chuyển động, toàn bộ ngưng tụ trên năm ngón tay phải, xuất hiện ngàn vạn tàn ảnh rồi hợp nhất chụp xuống. Dùng liên tục suốt mấy canh giờ phá tầng băng Đông Lâm Trì có lực tự phục hồi do dung hợp với cánh tay trái Diệp Mịch, giật tung nhiều khối băng lớn, tạo hố sâu bốn trượng.","congNang":["Ngưng tụ Đạo Cổ lực trên năm ngón tay, tạo ngàn vạn tàn ảnh hợp nhất chụp xuống phá phong ấn/tầng băng"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1673","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1673","loai":"thi triển","importance":"normal","giaiDoan":"Phá băng Đông Lâm Trì","text":"Vương Lâm thi triển Đạo Cổ bất diệt chỉ phá tầng băng Đông Lâm Trì có lực tự phục hồi, liên tục sử dụng suốt mấy canh giờ, giật tung nhiều khối băng lớn để lộ cánh tay trái Diệp Mịch.","anchor":"Đạo cổ lực trong cơ thể hắn ầm ầm chuyển động, toàn bộ ngưng tụ trên năm ngón tay phải"}]},"nguon":["@c1673"]},{"id":"that-dieu-kim-mon","name":"Thất Diện Kim Môn","cn":"","aliases":["Bảy kim môn","Kim môn"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Đường San"],"blurb":"Thần thông phòng hộ của đệ tam phi Đường San, triệu kim môn khổng lồ phát kim quang vạn trượng để đối kháng công kích.","detail":"Kim môn khổng lồ trôi tới phát kim quang vạn trượng đối kháng tiếng gầm. Bị tiếng gầm Dĩ Ti Chi Khôi phá hủy liên tiếp, bốn luồng kim quang cũng vỡ vụn. Chuỗi hạt châu sư tôn ban tặng có thể hóa thành bảy kim môn đồng thời hiện ra, uy lực mạnh hơn.","congNang":["Triệu kim môn phòng hộ, phát kim quang đối kháng công kích"],"nguoiTu":[{"ten":"Đường San","tuChuong":"@c1675","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1675","loai":"thi triển","importance":"normal","giaiDoan":"Đệ tam phi dùng kim môn chống Dĩ Ti Chi Khôi","text":"Đệ tam phi dùng kim môn phòng hộ chống tiếng gầm Dĩ Ti Chi Khôi, kim môn liên tục bị phá vỡ, bốn luồng kim quang cũng vỡ vụn.","anchor":"Kim môn lập tức phát ra kim quang vạn trượng, đối kháng với tiếng gầm kia"}]},"nguon":["@c1675"]},{"id":"bat-dao-tram-than-hon","name":"Bát Đao Trảm Thần Hồn","cn":"八刀斩神魂","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vân Dật Phong"],"blurb":"Bát Đao Trảm Thần Hồn là thần thông của Vân Dật Phong, vận dụng bảy thanh trường đao rút từ sương đen kết hợp phân thân thành bảy bản thể, bảy thân hợp nhất tạo hình đao thứ tám khổng lồ khai thiên có uy lực cự đại. Trong trận đấu với Vương Lâm, thần thông này bị Tê Thiên Thuật đại thành phá tan hoàn toàn.","detail":"Khi thi triển, người dùng rút ra bảy thanh trường đao từ đám sương đen, đồng thời phân thân thành bảy bản thể. Bảy bản thể mỗi thân đảm nhận một bộ phận cấu thành: hai thân làm cán đao, bốn thân làm thân đao, một thân làm ngọn đao — bảy thân nối liền tạo hình thanh đao thứ tám khổng lồ mang uy lực khai thiên. Vân Dật Phong thi triển thần thông này trong trận đấu với Vương Lâm, nhưng bị Tê Thiên Thuật đại thành phá tan hoàn toàn. Sau đó Vân Dật Phong uống đan dược thi triển lại để tấn công Chưởng Tôn.","congNang":["Từ đám sương đen rút ra bảy thanh trường đao @c1676","Phân thân thành bảy bản thể, mỗi thân đảm nhận vai trò cấu thành đao thứ tám @c1676","Bảy thân hợp nhất tạo hình đao thứ tám khổng lồ khai thiên, uy lực cự đại @c1676"],"nguoiTu":[{"ten":"Vân Dật Phong","tuChuong":"@c1676","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1676","loai":"thi triển","importance":"major","giaiDoan":"Xuất hiện và thi triển","text":"Vân Dật Phong thi triển Bát Đao Trảm Thần Hồn đấu Vương Lâm, bị phá tan hoàn toàn bởi Tê Thiên Thuật đại thành. Sau đó uống đan dược thi triển lại để tấn công Chưởng Tôn.","anchor":"Bát đao trảm thần hồn!"}]},"nguon":["@c1676"],"uyLuc":"Bảy thân hợp nhất thành đao thứ tám khai thiên có uy lực cự đại, tuy nhiên bị Vương Lâm dùng Tê Thiên Thuật đại thành phá tan hoàn toàn @c1676","dacDiem":"Kết hợp phân thân thuật và đao pháp thành một thể thống nhất, bảy bản thể không chiến đấu riêng lẻ mà đóng vai trò cấu kiện — hai thân làm cán, bốn thân làm thân, một thân làm ngọn — hợp thành hình dạng thanh đao thứ tám khổng lồ"},{"id":"chuong-diet-tam-dao","name":"Chưởng diệt tam đạo","cn":"掌灭三道","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Chưởng Tôn"],"blurb":"Chưởng diệt tam đạo là thần thông liên hoàn ba tầng của Chưởng Tôn, lần lượt gồm Đệ nhất diệt linh đạo, Đệ nhị diệt quỷ đạo và Đệ tam diệt thần đạo — mỗi tầng uy lực vượt trội tầng trước. Tầng cuối cùng phun máu vàng ngưng tụ thành kim ấn khổng lồ, đủ sức vượt qua Tê Thiên Thuật của Vương Lâm trong trận đối đầu tại @c1677.","detail":"Chưởng diệt tam đạo là thần thông chiến đấu liên hoàn ba tầng do Chưởng Tôn thi triển. Đệ nhất diệt linh đạo: hai tay kết vòng tròn phóng ra vô số kim quang kiếm sắc. Đệ nhị diệt quỷ đạo: hiện sơ dương phía sau lưng, tràn ngập sức mạnh thái sơ quy tắc. Đệ tam diệt thần đạo: phun máu vàng từ miệng, máu ngưng tụ thành kim ấn khổng lồ — là tầng mạnh nhất trong ba tầng. Trong trận giao phong tại @c1677, Chưởng Tôn thi triển đầy đủ cả ba tầng đối đầu Tê Thiên Thuật của Vương Lâm; hai tầng đầu bị phá, nhưng kim ấn tầng ba vượt qua được Tê Thiên Thuật. Tuy nhiên, kim ấn sau đó bị Huyền La biến thành pháp bảo thực chất.","congNang":["Đệ nhất diệt linh đạo: hai tay kết vòng tròn phóng ra vô số kim quang kiếm sắc @c1677","Đệ nhị diệt quỷ đạo: hiện sơ dương phía sau lưng, phát huy sức mạnh thái sơ quy tắc @c1677","Đệ tam diệt thần đạo: phun máu vàng ngưng tụ thành kim ấn khổng lồ, uy lực vượt trội hai tầng trước @c1677","Tấn công liên hoàn ba tầng, mỗi tầng uy lực mạnh hơn tầng trước @c1677"],"nguoiTu":[{"ten":"Chưởng Tôn","tuChuong":"@c1677","tangDatToi":"Đệ tam diệt thần đạo","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1677","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Chưởng Tôn thi triển đầy đủ ba tầng đối đầu Tê Thiên Thuật của Vương Lâm. Hai tầng đầu bị phá nhưng kim ấn tầng ba vượt qua giáng xuống Vương Lâm. Kim ấn sau đó bị Huyền La biến thành pháp bảo thực chất.","anchor":"Chưởng diệt tam đạo! Đệ nhất diệt linh đạo!"}]},"nguon":["@c1677"],"uyLuc":"Kim ấn tầng ba đủ sức vượt qua Tê Thiên Thuật của Vương Lâm trong trận đối đầu trực tiếp tại @c1677.","dacDiem":"Thần thông liên hoàn cấu trúc ba tầng leo thang uy lực; tầng cuối yêu cầu phun máu vàng làm dẫn chất ngưng tụ kim ấn, mang tính đánh đổi."},{"id":"nang-luc-bien-than-thong-thanh-phap-bao","name":"Năng lực biến thần thông hư ảo thành pháp bảo thực chất","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cấp cửu đại thiên tôn","hePhai":"Tiên Cương Cửu Dương","soHuu":["Huyền La Đại Thiên Tôn"],"blurb":"Năng lực cấp cửu đại thiên tôn thuộc Tiên Cương Cửu Dương, cho phép biến vật do thần thông biến hóa ra — vốn là hư ảo — thành pháp bảo thực chất. Được Huyền La thi triển tại chương 1677 khi biến kim ấn hư ảo của Chưởng Tôn thành vật thật lơ lửng trước Vương Lâm.","detail":"Tại chương 1677, Huyền La tùy ý chỉ tay dừng kim ấn — vốn là thần thông hư ảo do Chưởng Tôn ngưng tụ — rồi biến nó thành một pháp bảo thực chất. Chưởng Tôn xác nhận đây là năng lực \"thay trời đổi đất, lấy tạo hóa sinh vật\", chỉ có cửu đại thiên tôn thuộc Tiên Cương Cửu Dương mới có thể làm được. Năng lực này thể hiện quyền năng sáng tạo vật chất từ hư không, vượt qua giới hạn thông thường của thần thông biến hóa vốn chỉ tồn tại dưới dạng ảo.","congNang":["Biến vật do thần thông biến hóa ra (hư ảo) thành vật thực chất, tạo ra pháp bảo thật sự từ hư không @c1677"],"nguoiTu":[{"ten":"Huyền La Đại Thiên Tôn","tuChuong":"@c1677","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1677","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu lộ diện","text":"Huyền La tùy ý chỉ tay biến kim ấn hư ảo của Chưởng Tôn thành pháp bảo thực chất lơ lửng trước Vương Lâm, khiến Chưởng Tôn kinh hãi nhận ra thân phận cửu đại thiên tôn.","anchor":"Biến vật do thần thông biến hoá ra trở thành thực chất, chuyện thay trời đổi đất này, năng lực lấy tạo hoá để sinh vật này"}]},"nguon":["@c1677"],"uyLuc":"Tùy ý chỉ tay biến kim ấn hư ảo của Chưởng Tôn thành pháp bảo thực chất, được Chưởng Tôn thừa nhận là năng lực thay trời đổi đất, lấy tạo hóa sinh vật, chỉ cửu đại thiên tôn mới làm được @c1677","dacDiem":"Năng lực độc hữu của cửu đại thiên tôn thuộc Tiên Cương Cửu Dương, bản chất là dùng quyền năng cấp tạo hóa để chuyển hóa hư thành thực, không cần nguyên liệu hay quá trình luyện chế thông thường"},{"id":"than-thong-ac-hau-tim","name":"Thần thông ác hầu tím","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tiên Cương đại lục","soHuu":["Vân Dật Phong"],"blurb":"Thần thông từ Tiên Cương đại lục, tử quang hóa thành con khỉ màu tím, nhập thể kẻ địch theo thất khiếu phá hoại từ bên trong.","detail":"Vân Dật Phong thi triển tử quang hóa thành con khỉ màu tím tấn công Chưởng Tôn. Ác hầu theo thất khiếu nhập thể, xuất hiện hư ảnh trên mi tâm đối phương, gây cảm giác thân thể bị xé rách. Nguồn gốc từ Tiên Cương đại lục.","congNang":["Nhập thể kẻ địch qua thất khiếu, phá hoại từ bên trong","Xuất hiện hư ảnh trên mi tâm đối phương"],"nguoiTu":[{"ten":"Vân Dật Phong","tuChuong":"@c1678","tangDatToi":"Không rõ","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1678","loai":"thi triển","importance":"normal","giaiDoan":"Vân Dật Phong thi triển lần đầu trong trận vây Chưởng Tôn","text":"Vân Dật Phong hóa thần thông thành con khỉ màu tím, nhập thể Chưởng Tôn theo thất khiếu, xuất hiện hư ảnh trên mi tâm hắn.","anchor":"bị thần thông từ Tiên Cương đại lục của Vân Dật Phong kia nhập thể"}]},"nguon":["@c1678"]},{"id":"that-mon-hop-nhat-kim-long","name":"Thất môn hợp nhất — Kim long","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đường San (đệ tam phi)","soHuu":["Đường San"],"blurb":"Thần thông của Đường San, dùng hạt châu vàng triệu kim môn, thất môn hợp nhất hóa cự long màu vàng tấn công.","detail":"Đường San vung hạt châu vàng trên cổ tay, kim môn xuất hiện, thất môn hợp nhất, kim quang tràn ngập hóa thành cự long màu vàng lao ra tấn công đối phương.","congNang":["Hợp bảy cửa kim môn thành cự long vàng tấn công"],"nguoiTu":[{"ten":"Đường San","tuChuong":"@c1678","tangDatToi":"Thất môn hợp nhất","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1678","loai":"thi triển","importance":"normal","giaiDoan":"Đường San lần đầu thi triển thất môn hợp nhất","text":"Đường San vung hạt châu vàng, kim môn xuất hiện, thất môn hợp nhất hóa cự long màu vàng lao vào Chưởng Tôn.","anchor":"kim môn xuất hiện, lập tức dung hợp lại với nhau, sau khi thất môn hợp nhất"}]},"nguon":["@c1678"]},{"id":"phong-an-tu-ky-hieu-lam-mong","name":"Phong ấn tứ ký hiệu của Lam Mộng","cn":"","loai":"bi-thuat","loaiLabel":"Liên hợp thuật","phamCap":"","hePhai":"","soHuu":["Lam Mộng Đạo Tôn"],"blurb":"Liên hợp thuật do Lam Mộng Đạo Tôn làm chủ đạo, phối hợp Vân Dật Phong, Đường San và Thác Sâm dung hợp lam quang tạo bốn ký hiệu phong ấn, có khả năng phong bế toàn thân đối thủ cấp huyền kiếp trong ba nhịp thở.","detail":"Lam Mộng Đạo Tôn dùng tu vi cả đời hóa lam quang, kéo Vân Dật Phong, Đường San, Thác Sâm cùng dung hợp vào lam quang, ngưng tụ ra bốn ký hiệu phong ấn đánh thẳng lên người đối thủ. Thuật thức đã được thi triển trong trận chiến tại tầng hai cổ mộ nhằm phong ấn Chưởng Tôn ba nhịp thở.","congNang":["Phong ấn toàn thân đối thủ cấp huyền kiếp trong ba nhịp thở khi phối hợp bốn người @c1679"],"nguon":["@c1679"],"tabs":{"tienTrinh":[{"chuong":"@c1679","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Lam Mộng Đạo Tôn dùng tu vi cả đời làm chủ đạo, phối hợp Vân Dật Phong, Đường San, Thác Sâm dung hợp lam quang tạo bốn ký hiệu phong ấn, phong bế Chưởng Tôn ba nhịp thở, tạo cơ hội cho Vương Lâm dùng Mộng Đạo tế hồn.","anchor":"bốn ký hiệu phong ấn, trong lúc lam quang lóe lên lao thẳng tới Chưởng Tôn"}]},"uyLuc":"Phong bế được toàn thân đối thủ cấp huyền kiếp trong ba nhịp thở.","dacDiem":"Đòi hỏi bốn người phối hợp, lấy tu vi cả đời của Lam Mộng Đạo Tôn làm chủ đạo dung hợp thành lam quang, ngưng tụ bốn ký hiệu phong ấn."},{"id":"than-thong-nhip-tim","name":"Thần thông nhịp tim (đang cảm ngộ)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông Vương Lâm minh ngộ từ nhịp đập trái tim Diệp Mịch tại tầng cuối cùng vùng đất cổ mộ: dùng nhịp tim bản thân dẫn động nhịp tim đối phương, khiến vỡ tim hoặc khống chế. Hiện đang trong giai đoạn cảm ngộ, chưa hoàn chỉnh.","detail":"Tại tầng cuối cùng vùng đất cổ mộ, Vương Lâm cảm nhận sự hòa nhịp với trái tim Diệp Mịch và từ đó minh ngộ nguyên lý cốt lõi của thần thông này: dùng nhịp tim bản thân để dẫn động nhịp tim đối phương. Thần thông được tính toán kết hợp ba yếu tố — lôi bổn nguyên dùng để khuếch đại tiếng tim, Mộng Đạo khiến đối phương sinh ảo giác từ đó thay đổi nhịp tim, và hư hỏa trong hỏa bổn nguyên sẽ bùng lên khi nhịp tim đối phương biến đổi. Tuy nhiên, tới mốc ghi nhận mới nhất, thần thông vẫn đang ở giai đoạn cảm ngộ và chưa hoàn thành.","congNang":["Dùng nhịp tim bản thân dẫn động nhịp tim đối phương, có thể khiến đối phương vỡ tim mà chết hoặc gián tiếp khống chế @c1681"],"dacDiem":"Kết hợp lôi bổn nguyên (khuếch đại tiếng tim), Mộng Đạo (khiến đối phương sinh ảo giác thay đổi nhịp tim) và hư hỏa trong hỏa bổn nguyên (nhóm hư hỏa khi nhịp tim thay đổi); đang trong giai đoạn cảm ngộ chưa hoàn chỉnh.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1681","tangDatToi":"đang cảm ngộ","trangThai":"dang-tu"}],"trangThai":"đang cảm ngộ","tabs":{"tienTrinh":[{"chuong":"@c1681","loai":"xuất hiện","importance":"major","giaiDoan":"Cảm ngộ sơ bộ","text":"Vương Lâm minh ngộ nguyên lý dùng nhịp tim dẫn động nhịp tim đối phương từ sự hòa nhịp với trái tim Diệp Mịch. Tính toán kết hợp lôi bổn nguyên, Mộng Đạo và hư hỏa để sáng tạo thần thông mới, chưa hoàn thành.","anchor":"Dùng trái tim của bản thân dẫn động trái tim của người khác, thay đổi nhịp tim của đối phương"}]},"nguon":["@c1681"]},{"id":"ngu-hanh-kim-tien","name":"Ngũ hành kim tiên — Ngưng tụ kim thiên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Ngũ Hành","soHuu":["Lão già họ Mã"],"blurb":"Thần thông ngũ hành của lão già họ Mã, kim quang bùng lên biến bầu trời thành dòng sông ánh sáng, từ đó vươn ra bàn tay kim sắc khổng lồ tấn công.","detail":"Lão già họ Mã thi triển tại tầng thứ hai vùng đất cổ mộ. Kim quang bùng lên biến bầu trời thành dòng sông ánh sáng, từ trời vươn ra bàn tay kim sắc khổng lồ đánh về phía Chiến lão quỷ.","congNang":["Biến bầu trời thành kim thiên, triệu bàn tay kim sắc khổng lồ tấn công"],"nguoiTu":[{"ten":"Lão già họ Mã","tuChuong":"@c1681","tangDatToi":"","trangThai":"da-thi-trien"}],"tabs":{"tienTrinh":[{"chuong":"@c1681","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Lão già họ Mã thi triển tại ác chiến tầng thứ hai, biến bầu trời thành dòng sông kim quang, vươn bàn tay kim sắc khổng lồ đánh Chiến lão quỷ.","anchor":"Ngũ hành kim tiên! Ngưng tụ kim thiên!"}]},"nguon":["@c1681"]},{"id":"ngu-hanh-tho-tien","name":"Ngũ hành thổ tiên — Ngưng tụ hắc địa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Ngũ Hành","soHuu":["Lão già họ Mã"],"blurb":"Thần thông ngũ hành của lão già họ Mã, biến mặt đất thành vùng hắc ám, vươn ra bàn tay hắc khổng lồ tấn công.","detail":"Lão già họ Mã thi triển tại tầng thứ hai vùng đất cổ mộ. Mặt đất hóa vùng hắc ám, từ đó vươn ra bàn tay hắc khổng lồ đánh về phía Chiến lão quỷ, phối hợp cùng bàn tay kim sắc từ trên trời.","congNang":["Biến mặt đất thành hắc địa, triệu bàn tay hắc sắc khổng lồ tấn công"],"nguoiTu":[{"ten":"Lão già họ Mã","tuChuong":"@c1681","tangDatToi":"","trangThai":"da-thi-trien"}],"tabs":{"tienTrinh":[{"chuong":"@c1681","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Lão già họ Mã thi triển phối hợp cùng Ngũ hành kim tiên, biến mặt đất thành hắc địa, vươn bàn tay hắc khổng lồ đánh Chiến lão quỷ.","anchor":"Ngũ hành thổ tiên! Ngưng tụ hắc địa!"}]},"nguon":["@c1681"]},{"id":"tam-dong-loi-am","name":"Tâm Động Lôi Âm","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Tâm Động Lôi Âm là thần thông Vương Lâm đạt được sau khi hoàn thành truyền thừa Diệp Mịch, biến tiếng tim đập thành âm thanh duy nhất trong thiên địa, dẫn động tâm thần và trái tim đối phương khiến chúng đau đớn sụp đổ. Ngay cả cường giả huyền kiếp đỉnh phong cũng không thể chống đỡ trước uy lực của thuật này. (+) Tâm động lôi âm là cách Vương Lâm biến tiếng tim đập thành lôi âm trong cơ thể. [CAN-SOAT-GOP]","detail":"Sau khi hoàn thành truyền thừa của Diệp Mịch, Vương Lâm lĩnh ngộ thần thông Tâm Động Lôi Âm. Khi phát động, tiếng tim đập từ trái tim Vương Lâm truyền ra khuếch tán khắp thiên địa, trở thành âm thanh duy nhất tồn tại giữa trời đất, trực tiếp dẫn động tâm thần và trái tim đối phương, khiến trái tim họ đau đớn như bị xé nát mà không thể tự khống chế. Thuật này ảnh hưởng trên phạm vi diện rộng, không chỉ nhắm vào một mục tiêu đơn lẻ. Trong thực chiến, kẻ mạnh ở tầng huyền kiếp đỉnh phong như Chiến lão quỷ — vốn đã dung hợp hồn phách Thất Thải Tiên Tôn — cũng không chống nổi, và Huyền Vũ chiến tướng gần đạt cảnh giới Không Kiếp cũng bị đánh bại dưới uy lực này.","thuocTinh":"Âm — Tâm thần","nguonGoc":"Đạt được sau khi hoàn thành truyền thừa Diệp Mịch","uyLuc":"Kẻ huyền kiếp đỉnh phong như Chiến lão quỷ (dung hợp hồn phách Thất Thải Tiên Tôn) cũng không chống nổi, Huyền Vũ chiến tướng gần cảnh giới Không Kiếp cũng bị đánh bại.","dacDiem":"Tiếng tim đập trở thành âm thanh duy nhất trong thiên địa, ảnh hưởng diện rộng, tác động trực tiếp lên tâm thần và trái tim đối phương.","congNang":["Tiếng tim đập dẫn động tâm thần đối phương, khiến trái tim đau đớn như bị xé nát (@c1682)"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1682","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1682","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm phát động tiếng tim đập kinh thiên sau khi hoàn thành truyền thừa Diệp Mịch. Tiếng tim truyền vào tâm thần Chiến lão quỷ (dung hợp Thất Thải Tiên Tôn) khiến trái tim hắn đau đớn không thể khống chế. Trước đó tiếng tim cũng đánh bại Huyền Vũ chiến tướng ở cửa vào tầng cuối.","anchor":"tiếng thình thịch vang lên, giống như sấm dậy. Tiếng động từ trong thân thể Vương Lâm truyền ra"}]},"nguon":["@c1682","@c1809"]},{"id":"ngan-muc","name":"Ngân Mục","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đệ nhất tượng trong cửu khúc tam tượng","hePhai":"Cổ Tộc","soHuu":["Vương Lâm"],"blurb":"Ngân Mục là đệ nhất tượng (lưỡng khúc) trong hệ thống cửu khúc tam tượng, biểu hiện bằng hai mắt đều biến thành màu bạc. Công pháp này hình thành nhờ sự kết hợp giữa hồn huyết cổ Tổ và truyền thừa Diệp Mịch, ban cho Vương Lâm thị giác siêu phàm có thể nhìn thấy những điều người khác không thể thấy.","detail":"Ngân Mục thuộc hệ thống cửu khúc tam tượng — hệ thống biểu hiện khi tiên tổ hoặc cổ Tổ giáng trần, trong đó bát tượng là tiên, cửu khúc là cổ. Lưỡng khúc tương ứng đệ nhất tượng, biểu hiện cụ thể là ngân mục kim thân. Lão già họ Mã từng khẳng định rằng chỉ riêng truyền thừa Diệp Mịch là không đủ để có được ngân mục, ngay cả bản thân Diệp Mịch cũng không sở hữu đôi mắt bạc này — điều kiện tiên quyết là phải có hồn huyết cổ Tổ. Sau khi hoàn thành truyền thừa Diệp Mịch với sự hỗ trợ của hồn huyết cổ Tổ, hai mắt Vương Lâm biến thành màu bạc, kích hoạt ngân mục. Vương Lâm đã dùng ngân mục nhìn qua Huyền La Đại Thiên Tôn và mơ hồ thấy được điều gì đó mà không ai khác có thể nhìn thấy.","thuocTinh":"Cổ Tộc — Thị giác","nguonGoc":"Hồn huyết cổ Tổ + truyền thừa Diệp Mịch","uyLuc":"Dùng ngân mục nhìn qua Huyền La Đại Thiên Tôn, mơ hồ thấy được điều mà không ai khác nhìn thấy (@c1682).","dacDiem":"Đệ nhất tượng (lưỡng khúc) trong cửu khúc tam tượng, biểu hiện là hai mắt đều biến thành màu bạc; yêu cầu đồng thời hồn huyết cổ Tổ và truyền thừa Diệp Mịch mới có thể kích hoạt.","congNang":["Nhìn thấy những điều người khác không thể thấy, nhìn xuyên bản chất (@c1682)"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1682","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1682","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Hai mắt Vương Lâm biến thành ngân mục sau hoàn thành truyền thừa Diệp Mịch nhờ hồn huyết cổ Tổ. Huyền La Đại Thiên Tôn kích động nhận ra đây là đệ nhất tượng trong cửu khúc. Lão già họ Mã nhớ truyền thuyết lưỡng khúc là ngân mục kim thân.","anchor":"Hai mắt màu bạc! Nghe đồn tiên tổ khi giáng trần có cửu khúc tam tượng"}]},"nguon":["@c1682"]},{"id":"dao-co-vo-tien","name":"Đạo Cổ Vô Tiên","cn":"道古無仙","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tuyệt học Đạo cổ","hePhai":"Đạo cổ nhất mạch","soHuu":["Vương Lâm"],"blurb":"Tuyệt chiêu dung hợp sức mạnh tam tộc Đạo cổ (Cổ Thần, Cổ Yêu, Cổ Ma), triệu ra hư ảnh đầu lâu Cổ Tổ hóa đá thiên địa. Gốc từ thần miếu bộ tộc Đạo cổ, thuộc truyền thừa Diệp Mịch, là tuyệt học mạnh nhất trong hệ truyền thừa này.","detail":"Đạo Cổ Vô Tiên bắt nguồn từ thần miếu bộ tộc Đạo cổ, truyền thừa qua Diệp Mịch tới Vương Lâm. Chiêu thức gồm ba bước liên hoàn: thứ nhất — Thần Chấn binh tu liệt vị, dùng Cổ Thần cửu tinh xoay chuyển thiên địa quanh quyền; thứ hai — Yêu Thuật phong hỏa thành sơn, dùng Cổ Yêu bát tinh tạo tám cột phong hỏa nối thành lốc xoáy; thứ ba — Ma Đạo sinh tử nghịch động, dùng Cổ Ma cửu tinh chuyển hóa sức sống thành tử khí, ngưng tử khí từ vô số sinh linh thành biển chết. Cuối cùng dung hợp cả ba nhánh thành một chưởng, triệu ra hư ảnh đầu lâu Cổ Tổ khổng lồ cao ngang thiên địa, phun khí tức hóa đá toàn bộ vùng đất. Điều kiện thi triển yêu cầu đồng thời Cổ Thần cửu tinh, Cổ Ma cửu tinh và Cổ Yêu (hiện bát tinh, thiếu mắt trái nên chưa đạt cửu tinh). Thi triển xong sẽ kiệt sức, không thể dùng lần hai","thuocTinh":"Đạo cổ tam tộc","nguonGoc":"Thần miếu bộ tộc Đạo cổ, truyền thừa Diệp Mịch","yeuCau":"Cổ Thần cửu tinh + Cổ Ma cửu tinh + Cổ Yêu bát tinh trở lên","uyLuc":"Hóa đá toàn bộ cổ mộ nhiều tầng cùng Chiến lão quỷ và hai hồn Thất Thải Tiên Tôn trong một chưởng @c1683","dacDiem":"Dung hợp sức mạnh ba nhánh Cổ tộc (Cổ Thần, Cổ Yêu, Cổ Ma) thành một, triệu hư ảnh Cổ Tổ — tuyệt học mạnh nhất trong truyền thừa Diệp Mịch; thi triển xong kiệt sức, không thể dùng lần hai trong thời gian ngắn","congNang":["Dung hợp sức mạnh Cổ Thần cửu tinh, Cổ Ma cửu tinh và Cổ Yêu bát tinh thành một chưởng duy nhất @c1683","Triệu hư ảnh đầu lâu Cổ Tổ khổng lồ cao ngang thiên địa, phun khí tức hóa đá toàn bộ khu vực mục tiêu @c1683"],"cacTang":[{"ten":"Thần Chấn — Binh Tu Liệt Vị","moTa":"Cổ Thần cửu tinh xoay tròn dung nhập quyền, thiên địa xoay quanh","chuong":"@c1683"},{"ten":"Yêu Thuật — Phong Hỏa Thành Sơn","moTa":"Cổ Yêu bát tinh tạo tám cột phong hỏa nối thành lốc","chuong":"@c1683"},{"ten":"Ma Đạo — Sinh Tử Nghịch Động","moTa":"Cổ Ma cửu tinh chuyển hóa sức sống thành tử khí, ngưng tử khí từ toàn bộ cổ mộ","chuong":"@c1683"}],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1683","tangDatToi":"Hợp nhất tam tộc","trangThai":"dang-tu"}],"trangThai":"hoat-dong","capNhatToi":"@c1683","dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1683","loai":"thi-trien","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm lần đầu thi triển Đạo Cổ Vô Tiên tại cổ mộ, dung hợp tam tộc triệu ra hư ảnh đầu lâu Cổ Tổ hóa đá toàn bộ cổ mộ và Chiến lão quỷ cùng hai hồn Thất Thải. Dù kiệt sức, Chiến lão quỷ vẫn phá hóa đá thoát thân.","anchor":"Thần. Yêu. Ma. Đạo cổ vô tiên!"}]},"nguon":["@c1683"]},{"id":"van-dao-thien-thuat","name":"Vân Đạo Thiên Thuật","cn":"云道天术","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Tam đại tối cường thần thông Đông Lâm Tông","hePhai":"Đông Lâm Tông","soHuu":["Vương Lâm","Thất Thải Tiên Tôn"],"blurb":"Vân Đạo Thiên Thuật là một trong tam đại tối cường thần thông của Đông Lâm Tông, mỗi thế hệ chỉ truyền cho duy nhất một người. Sư tôn Liên Đạo Phi truyền khẩu quyết nhập môn và tổ chức thử thách tuyển chọn người kế thừa.","detail":"Vân Đạo Thiên Thuật thuộc hàng tam đại tối cường thần thông của Đông Lâm Tông, tuân thủ quy tắc mỗi thế hệ chỉ một đệ tử được thụ truyền. Khẩu quyết nhập môn yêu cầu hành giả vận chuyển vân khí trong thân thể trọn một vòng tuần hoàn; mây mù bao phủ càng nồng đậm, xuất hiện hư ảnh biến ảo thì tư chất càng cao, mỏng nhạt thì không đủ tư cách. Tốc độ vận chuyển cũng là tiêu chí then chốt — kỷ lục nhanh nhất trong lịch sử Đông Lâm Tông là bảy nhịp thở. Vương Lâm từng đạt tám nhịp thở, mây mù tràn ngập phân nửa đại điện và hóa thành rồng lớn. Khẩu quyết có câu biến tấu từ Đạo Đức Kinh. Sư tôn Liên Đạo Phi chủ trì truyền thụ khẩu quyết nhập môn và tổ chức cuộc thử thách giữa các đệ tử để chọn người kế thừa @c1685.","thuocTinh":"Vân đạo","nguonGoc":"Đông Lâm Tông tam đại tối cường thần thông","dacDiem":"Mỗi thế hệ chỉ một người được học; khẩu quyết nhập môn có câu biến tấu từ Đạo Đức Kinh; tiêu chí tuyển chọn dựa vào nồng độ mây mù và tốc độ vận chuyển vân khí trong thân.","congNang":["Vận chuyển vân khí trong thân thể tạo mây mù biến ảo bao phủ xung quanh","Mây mù có thể hóa rồng, nuốt sương mù của đối thủ"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1685","tangDatToi":"Khẩu quyết nhập môn","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1685","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện, Vương Lâm đạt tư cách học","text":"Sư tôn Liên Đạo Phi truyền khẩu quyết nhập môn Vân Đạo Thiên Thuật, tổ chức cuộc thử thách giữa Tô Đạo và Chu Lập. Vương Lâm nghịch chuyển ký ức, tám nhịp thở vận chuyển xong, mây mù hóa rồng nuốt sương mù Chu Lập, giành tư cách đệ tử chính hệ.","anchor":"một trong tam đại tối cường thần thông của Đông Lâm Tông"}]},"nguon":["@c1685","@c1688"]},{"id":"that-thai-tien-thuat","name":"Thất Thải Tiên Thuật","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Thuật pháp bậc nhất Đông Lâm Tông","hePhai":"Đông Lâm Tông","soHuu":["Chu Lập"],"blurb":"Thuật pháp bậc nhất của Đông Lâm Tông, được truyền cho người không đủ tư cách học Vân Đạo Thiên Thuật.","detail":"Trong ký ức gốc, Tô Đạo nhận thuật này vì thua cuộc thử thách vân khí. Sau khi Vương Lâm nghịch chuyển ký ức, Chu Lập trở thành người nhận Thất Thải Tiên Thuật thay thế.","nguonGoc":"Đông Lâm Tông","nguoiTu":[{"ten":"Thất Thải Tiên Tôn","tuChuong":"@c1685","tangDatToi":"Không rõ","trangThai":"ky-uc-goc"},{"ten":"Chu Lập","tuChuong":"@c1685","tangDatToi":"Không rõ","trangThai":"ky-uc-nghich-chuyen"}],"tabs":{"tienTrinh":[{"chuong":"@c1685","loai":"xuất hiện","importance":"normal","giaiDoan":"Hé lộ trong cuộc truyền thừa","text":"Thuật pháp bậc nhất Đông Lâm Tông, truyền cho người thua trong cuộc thử thách chọn truyền nhân Vân Đạo Thiên Thuật. Ký ức gốc Tô Đạo nhận, ký ức nghịch chuyển Chu Lập nhận.","anchor":"vi sư sẽ truyền Thất Thải Tiên Thuật cho ngươi"}]},"nguon":["@c1685"]},{"id":"bon-nguyen-chan-than","name":"Bổn Nguyên Chân Thân","cn":"本源真身","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đạo Cổ","soHuu":["Vương Lâm"],"blurb":"Bổn Nguyên Chân Thân là hình thái tu luyện bổn nguyên hiếm thấy: khi mỗi đạo bổn nguyên đạt viên mãn, nó tự ngưng tụ thành một chân thân có hình dáng giống chủ nhân nhưng mang đặc trưng riêng của đạo bổn nguyên tương ứng. Tám chân thân có thể hiệp lực xuất chiêu tạo uy lực khổng lồ, và nếu đạt đủ chín chân thân sẽ cửu cửu quy nhất, mở ra con đường bước vào Không Huyền. (+) Bổn nguyên chân thân là chân thân được ngưng tụ từ bổn nguyên, phân biệt theo thuộc tính bổn nguyên của người tu. Chương này nêu rõ Vương Lâm có hỏa bổn nguyên chân thân, còn Thanh Ngưu chân nhân có hàn bổn nguyên chân thân. [CAN-SOAT-GOP]","detail":"Bổn Nguyên Chân Thân là hiện tượng chưa từng được Vương Lâm nghe nói tới trước khi tự thân trải nghiệm. Khi nhập Đông Lâm Trì, bảy đạo bổn nguyên của hắn — hỏa, lôi, sinh tử, nhân quả, chân giả, sát lục, cấm chế — lần lượt đạt viên mãn và mỗi đạo ngưng tụ thành một chân thân, tổng cộng bảy chân thân. Thủy bổn nguyên là đạo thứ tám. Mỗi chân thân mang hình dáng của chủ nhân song phản ánh đặc trưng riêng biệt của đạo bổn nguyên mà nó đại diện. Tám chân thân khi cùng xuất chiêu sẽ gia tăng uy lực đến mức cực lớn. Theo quy luật tu luyện, nếu có đủ bổn nguyên thứ chín, chín chân thân sẽ đạt cửu cửu quy nhất — điều kiện tiên quyết để bước vào cảnh giới Không Huyền.","congNang":["Mỗi đạo bổn nguyên khi đạt viên mãn tự ngưng tụ thành một chân thân hình dáng giống chủ nhân, mang đặc trưng riêng của đạo bổn nguyên đó @c1689","Tám chân thân có thể cùng lúc xuất chiêu, uy lực cộng hưởng cực lớn","Đạt đủ chín chân thân sẽ cửu cửu quy nhất, có thể bước vào cảnh giới Không Huyền"],"cacTang":[{"ten":"Tám bổn nguyên chân thân","moTa":"Hỏa, lôi, sinh tử, nhân quả, chân giả, sát lục, cấm chế, thủy — mỗi đạo một chân thân","chuong":"@c1689"},{"ten":"Cửu cửu quy nhất (chưa đạt)","moTa":"Cần bổn nguyên thứ chín để hoàn thành, bước vào Không Huyền","chuong":"@c1689"}],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1689","tangDatToi":"Tám bổn nguyên chân thân (hư ảo trong ký ức)","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1689","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện — tám chân thân ngưng tụ","text":"Vương Lâm nhập Đông Lâm Trì, bảy đạo bổn nguyên đạt viên mãn lần lượt ngưng tụ thành bảy chân thân. Thủy bổn nguyên hấp thu nước ao còn lại đại thành, ngưng tụ chân thân thứ tám. Tám chân thân cùng đánh ra chưởng mở đại môn động phủ giới.","anchor":"bổn nguyên tiến hóa, ngưng tụ ra chân thân của bổn nguyên mà hắn chưa bao giờ nghe thấy"}]},"nguon":["@c1689","@c1732"],"uyLuc":"Tám chân thân đồng thời đánh ra chưởng, tạo uy lực khổng lồ vượt xa đơn thân xuất chiêu.","dacDiem":"Mỗi chân thân tương ứng một trong tám đạo bổn nguyên (hỏa, lôi, sinh tử, nhân quả, chân giả, sát lục, cấm chế, thủy), hình dáng giống chủ nhân nhưng mang khí chất và đặc trưng riêng biệt của đạo bổn nguyên mà nó đại diện. Đây là hình thái tu luyện bổn nguyên mà Vương Lâm chưa từng nghe nói trước khi"},{"id":"thien-duong-luan-hoi-chuyen-the-thuat","name":"Thiên Dương luân hồi chuyển thế thuật","cn":"天阳轮回转世术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ (cực cao, Đại Thiên Tôn thi triển)","hePhai":"Đạo Cổ nhất mạch","soHuu":["Huyền La Đại Thiên Tôn"],"blurb":"Thiên Dương luân hồi chuyển thế thuật là thần thông do Huyền La Đại Thiên Tôn sở hữu, cho phép sinh linh chuyển thế đầu thai tại Tiên Cương đại lục với huyết mạch bản địa, đối kháng trực tiếp pháp tắc do Cổ Tổ và Tiên Tổ định ra cấm sinh linh ngoại lai bước vào. Thuật này đòi hỏi đại giá từ người thi triển và đi kèm nhiều hạn chế nghiêm ngặt về trí nhớ, thời gian cùng địa điểm đầu thai.","detail":"Tại mốc @c1692, Huyền La Đại Thiên Tôn đề xuất thi triển Thiên Dương luân hồi chuyển thế thuật nhằm đưa bằng hữu Vương Lâm rời khỏi động phủ giới tới Tiên Cương đại lục, nơi bị pháp tắc của Cổ Tổ và Tiên Tổ ngăn cấm sinh linh không mang huyết mạch bản địa tiến vào. Thuật này vận hành theo nguyên lý luân hồi chuyển thế: sinh linh được đầu thai lại hoàn toàn, khi sinh ra sẽ mang huyết mạch bản địa của Tiên Cương đại lục, qua đó né tránh quy tắc huyết mạch. Tuy nhiên, cái giá là trí nhớ bị phủ kín hoàn toàn sau khi chuyển thế, cần có người tìm tới mới có thể thức tỉnh. Thời gian đầu thai bất định, có thể từ vài năm cho tới hàng ngàn năm, và địa điểm đầu thai cũng không thể xác định trước. Bản thân Huyền La phải trả đại giá mới có thể thi triển. Ngoài ra, thuật này không áp dụng được cho hồn p","thuocTinh":"Luân hồi, chuyển thế","nguonGoc":"Huyền La Đại Thiên Tôn sở hữu","uyLuc":"Có khả năng đối kháng pháp tắc do Cổ Tổ và Tiên Tổ Tiên Cương đại lục định ra, cho phép sinh linh ngoại lai chuyển thế thành người bản địa mang huyết mạch Tiên Cương.","dacDiem":"Trí nhớ của người chuyển thế bị phủ kín hoàn toàn, cần người khác tìm tới thức tỉnh; thời gian đầu thai bất định từ vài năm tới hàng ngàn năm; địa điểm đầu thai không thể xác định trước; người thi triển phải trả đại giá; không áp dụng cho hồn phách không hoàn chỉnh.","congNang":["Chuyển thế đầu thai sinh linh tại Tiên Cương đại lục, sinh ra với huyết mạch bản địa, vượt qua quy tắc cấm sinh linh ngoại lai @c1692","Đối kháng pháp tắc Tiên Cương đại lục do Cổ Tổ và Tiên Tổ định ra @c1692"],"nguoiTu":[{"ten":"Huyền La Đại Thiên Tôn","tuChuong":"@c1692","tangDatToi":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1692","loai":"xuất hiện","importance":"major","giaiDoan":"Đề xuất lần đầu","text":"Huyền La Đại Thiên Tôn đề xuất thi triển Thiên Dương luân hồi chuyển thế thuật để đối kháng pháp tắc Tiên Cương, đưa bằng hữu Vương Lâm chuyển thế đầu thai tại Tiên Cương đại lục.","anchor":"thi triển Thiên Dương luân hồi chuyển thế thuật"}]},"nguon":["@c1692"]},{"id":"bay-dao-bon-nguyen","name":"Bảy đạo bổn nguyên","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Đạo Cổ","soHuu":["Vương Lâm"],"blurb":"Vương Lâm đồng thời vận chuyển bảy đạo bổn nguyên trong cơ thể, có thể ngưng tụ thành binh khí dung hợp khí tức Đạo Cổ.","detail":"Vương Lâm vận chuyển đồng thời bảy đạo bổn nguyên, ngưng tụ trong lòng bàn tay thành thanh kiếm ánh sáng dung hợp khí tức Đạo Cổ, uy lực kinh người.","congNang":["Ngưng tụ bổn nguyên + Đạo Cổ khí tức tạo binh khí"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1695","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1695","loai":"thi triển","importance":"normal","giaiDoan":"Ngưng tụ kiếm bổn nguyên tặng Mộc Băng Mi","text":"Vương Lâm đồng thời vận chuyển bảy đạo bổn nguyên, ngưng tụ thành thanh kiếm ánh sáng dung hợp khí tức Đạo Cổ, tặng cho Mộc Băng Mi trước khi rời đi.","anchor":"bảy đạo bổn nguyên trong cơ thể đồng thời vận chuyển, ngưng tụ trong lòng bàn tay hắn"}]},"nguon":["@c1695"]},{"id":"cuu-duong-dai-thien-ton-luc","name":"Cửu Dương Đại Thiên Tôn lực","cn":"九阳大天尊力","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đại Thiên Tôn","hePhai":"Cửu Dương","soHuu":["Huyền La"],"blurb":"Sức mạnh bản thân của Huyền La với tư cách Cửu Dương Đại Thiên Tôn, có thể biến thần thông vô hình thành vật thật có thể chạm cầm cảm nhận.","detail":"Huyền La dùng Cửu Dương Đại Thiên Tôn lực tạo ra mặt trời đỏ như máu to bằng nắm tay, vật chất hóa thần thông vô hình thành thực thể. Trao cho Vương Lâm để khuếch đại ý cảnh Mộng Đạo Thuật vô hạn, giúp phong ấn ký ức mọi người vào mộng trước khi chuyển thế.","congNang":["Biến thần thông vô hình thành vật thật có thể chạm cầm","Mở rộng ý cảnh thần thông vô hạn khi trao cho người khác sử dụng"],"nguon":["@c1696"]},{"id":"tran-phap-gioi-noi-gioi-ngoai","name":"Trận pháp giới nội–giới ngoại","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Trận pháp do Vương Lâm năm xưa bố trí ở ranh giới giữa giới nội và giới ngoại Thái Cổ Tinh Thần.","detail":"Trận pháp do Vương Lâm bố trí tại ranh giới giữa giới nội và giới ngoại Thái Cổ Tinh Thần. Vương Lâm dựa vào quyết tâm thông qua không dừng lại để vượt qua.","tabs":{"tienTrinh":[{"chuong":"@c1697","loai":"nhắc tới","importance":"normal","giaiDoan":"Vương Lâm vượt qua","text":"Vương Lâm vượt qua trận pháp do chính hắn năm xưa bố trí ở ranh giới giới nội–giới ngoại Thái Cổ Tinh Thần để truy bắt tam tôn.","anchor":"Trận pháp mới ở giữa hai giới là do Vương Lâm năm đó bố trí ra"}]},"nguon":["@c1697"]},{"id":"hon-huyen","name":"Hồn Huyễn","cn":"","aliases":["Huyễn Thuật Đại Hồn Môn"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Đại Hồn Môn","soHuu":["Phàn San Mộng"],"blurb":"Đặc trưng cốt lõi của Đại Hồn Môn, ảo thuật tu luyện tới cực hạn có thể hóa thành cửu trọng, uy lực cực kỳ đáng sợ.","detail":"Tu luyện nặng về Huyễn Thuật, đạt tới cực hạn thì hóa thành cửu trọng. Phàn San Mộng đang tu luyện và đã dùng được một số thủ đoạn.","congNang":["Ảo thuật cửu trọng — tu tới cực hạn có thể hóa thành cửu trọng, cực kỳ đáng sợ"],"nguoiTu":[{"ten":"Phàn San Mộng","tuChuong":"@c1706","tangDatToi":"Chưa rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1706","loai":"xuất hiện","importance":"normal","giaiDoan":"Giới thiệu nền","text":"Được giới thiệu là đặc trưng cốt lõi Đại Hồn Môn, tu tới cực hạn hóa cửu trọng, Phàn San Mộng đang tu.","anchor":"Nghe nói ảo thuật của Đại Hồn Môn tu luyện tới cực hạn có thể hóa thành cửu trọng"}]},"nguon":["@c1706"]},{"id":"khoi-loi-thuat-thuong-long-tong","name":"Khôi Lỗi Thuật Thương Long Tông","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Thương Long Tông","soHuu":["Đỗ Thanh"],"blurb":"Khôi Lỗi Thuật của Thương Long Tông có điểm thần kỳ khác: có thể chuyển đổi với thân thể, đạt mục đích vạn cổ bất diệt.","detail":"Khác với Khôi Lỗi Thuật thông thường, thuật này cho phép chuyển đổi khôi lỗi với thân thể, đạt mục đích vạn cổ bất diệt. Khôi lỗi tốt nhất luyện từ gỗ đặc thù hoặc thân thể hung thú/tu sĩ. Đỗ Thanh, thái thượng trưởng lão Thương Long Tông, bản thân chính là một khôi lỗi đạt Không Kiếp.","congNang":["Chuyển đổi khôi lỗi với thân thể, đạt mục đích vạn cổ bất diệt"],"nguoiTu":[{"ten":"Đỗ Thanh","tuChuong":"@c1706","tangDatToi":"Không Kiếp (khôi lỗi hóa)","trangThai":"da-thanh"}],"tabs":{"tienTrinh":[{"chuong":"@c1706","loai":"xuất hiện","importance":"normal","giaiDoan":"Giới thiệu nền","text":"Được giới thiệu là bí thuật cốt lõi Thương Long Tông, cho phép chuyển đổi thân thể với khôi lỗi để vạn cổ bất diệt. Đỗ Thanh chính là khôi lỗi đạt Không Kiếp.","anchor":"Nhưng Khôi Lỗi Thuật của Thương Long Tông lại có điểm thần kỳ khác, có thể chuyển đổi với thân thể, đạt được mục đích vạn cổ bất diệt."}]},"nguon":["@c1706"]},{"id":"tran-phap-luyen-che-khoi-loi","name":"Trận pháp luyện chế khôi lỗi (Thương Long Tông)","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Thương Long Tông","soHuu":["Khang Nhân"],"blurb":"Trận pháp mười trượng trong động phủ, tỏa khí tức màu tím quỷ dị, vận chuyển bằng ấn quyết kết hợp tài liệu và hút địa hỏa từ lòng đất để luyện người/xác thành khôi lỗi.","detail":"Trận pháp chuyên dụng của Thương Long Tông dùng luyện chế khôi lỗi. Khí tức tím quỷ dị tỏa ra từ trận, kích hoạt bằng ấn quyết và mười phần tài liệu luyện khôi lỗi. Hút địa hỏa từ sâu trong lòng đất, sóng nhiệt tràn ngập động phủ. Lượng địa hỏa bị lấy lớn tới mức trưởng bối tu vi Không Niết sơ kỳ cách xa cũng cảm nhận được.","congNang":["Luyện chế khôi lỗi từ người/xác, cần phối hợp tài liệu và địa hỏa"],"tabs":{"tienTrinh":[{"chuong":"@c1707","loai":"xuất hiện","importance":"normal","giaiDoan":"Khang Nhân kích hoạt luyện Vương Lâm","text":"Khang Nhân đưa Vương Lâm vào trận, dốc mười phần tài liệu, hút địa hỏa từ lòng đất. Địa hỏa không tổn thương Vương Lâm mà ngược lại chui vào cơ thể hắn như hưng phấn.","anchor":"Một luồng địa hỏa bị trận pháp này mạnh mẽ hấp thu từ sâu trong lòng đất"}]},"capNhatToi":"@c1707","nguon":["@c1707"]},{"id":"tran-phap-luyen-khoi-loi-khang-nhan","name":"Trận pháp luyện khôi lỗi (của Khang Nhân)","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Thương Long Tông","soHuu":["Khang Nhân"],"blurb":"Trận pháp do Khang Nhân bố trí dưới thân thi thể, dùng địa hỏa vận hành để cải tạo thân thể thành khôi lỗi.","detail":"Trận pháp bố trí dưới thân Vương Lâm, truyền lực lượng kỳ dị vào cơ thể nhằm luyện hóa thành khôi lỗi. Vận hành bằng địa hỏa của dãy núi. Bị Vương Lâm hút sạch địa hỏa khiến trận pháp nổ tung, hoàn toàn tan rã.","congNang":["Luyện hóa thi thể thành khôi lỗi, truyền lực lượng cải tạo thân thể"],"tabs":{"tienTrinh":[{"chuong":"@c1708","loai":"thi triển","importance":"normal","giaiDoan":"Bị phá hủy","text":"Khang Nhân bố trí trận pháp luyện khôi lỗi từ thi thể Vương Lâm, vận hành bằng địa hỏa. Vương Lâm hút sạch địa hỏa khiến trận pháp nổ tung hoàn toàn.","anchor":"một luồng lực lượng kỳ dị từ trận pháp nọ truyền ra, như muốn chui vào cơ thể hắn"}]},"nguon":["@c1708"]},{"id":"dao-hon-thuat","name":"Đạo Hồn Thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đạo pháp trấn phái Thương Long Tông","hePhai":"Thương Long Tông / Đại Hồn Môn","soHuu":["Thương Long Tông"],"blurb":"Đạo Hồn Thuật là thần thông trấn phái của Thương Long Tông, bắt nguồn từ Đạo Bộ Mộc của Đại Hồn Môn. Khi thi triển, cả vạn tu sĩ đồng thanh niệm chú tạo lực lượng kỳ dị có thể hóa tan đạo thuật và chia lìa linh hồn đối phương.","detail":"Đạo Hồn Thuật vốn là thần thông thuộc Đạo Bộ Mộc của Đại Hồn Môn, được ban cho Thương Long Tông nhờ quan hệ sâu đậm giữa lão tổ tông môn này với Đại Hồn Môn. Thuật pháp đòi hỏi đông đảo tu sĩ đồng thanh thi triển, sức mạnh tỉ lệ thuận với số người tham gia. Tại mốc @c1709, Triệu trưởng lão hạ lệnh bốn trưởng lão cùng cả vạn đệ tử bỏ qua Thiên Thủy Trận để đồng thanh thi triển Đạo Hồn Thuật. Khi phát động, cả vạn người đồng thanh niệm hai chữ, tạo ra luồng lực lượng kỳ dị nhắm vào linh hồn đối phương. Thuật này từng tấn công Vương Lâm khiến tâm thần chấn động, song bị Tâm Động Lôi Âm đối kháng.","nguonGoc":"Đạo Bộ Mộc — thần thông của Đại Hồn Môn, ban cho Thương Long Tông","congNang":["Hóa tan đạo thuật của đối phương khi cả vạn người đồng thanh thi triển @c1709","Chia lìa linh hồn đối phương, gây chấn động tâm thần @c1709"],"dacDiem":"Cần nhiều người đồng thanh thi triển, sức mạnh tỉ lệ thuận với số người tham gia; tấn công trực chỉ linh hồn đối phương.","nguoiTu":[{"ten":"Thương Long Tông (toàn tông)","tuChuong":"@c1709","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1709","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Triệu trưởng lão hạ lệnh bốn trưởng lão và cả vạn đệ tử bỏ qua Thiên Thủy Trận, đồng thanh thi triển Đạo Hồn Thuật tấn công hồn phách Vương Lâm. Bị Tâm Động Lôi Âm đối kháng.","anchor":"Đạo Bộ Mộc là thần thông của Đại Hồn Môn, lão tổ của Thương Long Tông có quan hệ sâu đậm với Đại Hồn Môn nên mới được ban thưởng thần thông này"}]},"capNhatToi":"@c1709","nguon":["@c1709"],"uyLuc":"Cả vạn tu sĩ đồng thanh niệm chú tạo luồng lực lượng kỳ dị, hóa tan đạo thuật và chia lìa linh hồn đối phương, khiến Vương Lâm tâm thần chấn động, nhưng bị Tâm Động Lôi Âm đối kháng."},{"id":"thien-thuy-tran","name":"Thiên Thủy Trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"","hePhai":"Thương Long Tông","soHuu":["Thương Long Tông"],"blurb":"Trận pháp của Thương Long Tông, bị bỏ qua theo lệnh Triệu trưởng lão để chuyển sang thi triển Đạo Hồn Thuật chống Vương Lâm.","detail":"Trận pháp phòng thủ hoặc tấn công của Thương Long Tông. Khi Vương Lâm định rời đi, Triệu trưởng lão ra lệnh bỏ qua Thiên Thủy Trận, thay bằng Đạo Hồn Thuật.","tabs":{"tienTrinh":[{"chuong":"@c1709","loai":"nhắc tới","importance":"bridge","giaiDoan":"Bị bỏ qua","text":"Bị bỏ qua theo lệnh Triệu trưởng lão để chuyển sang thi triển Đạo Hồn Thuật.","anchor":"bỏ qua Thiên Thủy trận, thi triển Đạo Hồn Thuật"}]},"capNhatToi":"@c1709","nguon":["@c1709"]},{"id":"thuat-rut-hon","name":"Thuật rút hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thuật rút hồn là thần thông Vương Lâm học được ở động phủ giới, cho phép rút linh hồn của địa hỏa mạch hóa thành hỏa long khổng lồ, tương tự nguyên lý rút Sơn hồn và Tinh hồn. Tại thời điểm thi triển ở Thương Long Tông, uy lực đủ phá sập cả ngọn núi, nhưng bị hạn chế bởi tu vi nên chỉ rút được phân mạch chứ chưa rút được chủ mạch.","detail":"Thuật rút hồn là thần thông Vương Lâm tu luyện được tại động phủ giới, vận dụng cùng nguyên lý với thuật rút Sơn hồn và Tinh hồn đã biết từ trước, nhưng đối tượng là linh hồn của địa hỏa mạch nằm sâu dưới lòng đất. Lần thi triển đầu tiên được ghi nhận là tại Thương Long Tông (@c1710), Vương Lâm rút hồn phân mạch địa hỏa ẩn dưới dãy núi, hóa thành hỏa long dài mấy vạn trượng, sức mạnh đủ phá sập cả ngọn núi. Tuy nhiên, do tu vi thời điểm đó còn hạn chế, hắn chỉ có thể rút được hồn của phân chi địa hỏa mạch chứ chưa đủ sức rút hồn chủ mạch, cho thấy thuật này còn tiềm năng phát triển theo cảnh giới của người thi triển.","thuocTinh":"Hỏa","nguonGoc":"Học ở động phủ giới","uyLuc":"Rút hồn phân mạch địa hỏa hóa hỏa long mấy vạn trượng, uy lực phá sập cả ngọn núi tại Thương Long Tông.","dacDiem":"Tương tự nguyên lý rút Sơn hồn và Tinh hồn, nhưng đối tượng là địa hỏa mạch; uy lực và phạm vi bị giới hạn theo tu vi người thi triển — ở cảnh giới hiện tại chỉ rút được phân mạch, chưa đủ sức rút hồn chủ mạch.","congNang":["Rút linh hồn của phân mạch địa hỏa dưới lòng đất, hóa thành hỏa long khổng lồ mấy vạn trượng (@c1710)","Phá hủy địa hình quy mô lớn — phá sập cả ngọn núi (@c1710)"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1710","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1710","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển tại Tiên Cương","text":"Vương Lâm thi triển thuật rút hồn tại Thương Long Tông, rút hồn phân mạch địa hỏa dưới dãy núi hóa thành hỏa long mấy vạn trượng, phá sập toàn bộ ngọn núi chứa động phủ.","anchor":"tương tự như thần thông rút Sơn hồn hay tinh hồn. Lần này hắn rút ra là hồn của địa hỏa mạch"}]},"nguon":["@c1710"]},{"id":"than-thong-anh-sang-xam","name":"Thần thông ánh sáng xám","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thương Long Tông","soHuu":["Đỗ Thanh"],"blurb":"Thần thông của tông chủ Đỗ Thanh, toàn thân lóe ánh sáng xám tràn vào thân thể đối phương, biến Nguyên Thần hoặc thể xác thành khôi lỗi.","detail":"Đỗ Thanh thi triển khi trừng phạt trưởng lão Tôn Mộng — ánh sáng màu xám từ toàn thân tràn vào thân thể Nguyên Thần, biến đối tượng thành khôi lỗi bị phong ấn.","congNang":["Biến Nguyên Thần/thân thể thành khôi lỗi"],"nguoiTu":[{"ten":"Đỗ Thanh","tuChuong":"@c1711","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1711","loai":"thi triển","importance":"normal","giaiDoan":"Lần thi triển đầu tiên được ghi nhận","text":"Đỗ Thanh thi triển thần thông ánh sáng xám biến trưởng lão Tôn Mộng (chỉ còn Nguyên Thần) thành khôi lỗi, phong ấn trừng phạt.","anchor":"Không biết thiếu niên này thi triển thần thông gì mà toàn thân lóe lên ánh sáng màu xám"}]},"nguon":["@c1711"]},{"id":"khai-mo-khong-gian-tru-vat-tu-than-the","name":"Khai mở Không Gian trữ vật từ thân thể","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Tiên Cương đại lục","soHuu":[],"blurb":"Phương pháp trữ vật của tu sĩ Tiên Cương — khai mở Không Gian trữ vật từ trong thân thể, không bị hạn chế địa điểm, khác hẳn cách từ động phủ giới.","detail":"Tu sĩ Tiên Cương khai mở Không Gian trữ vật từ trong thân thể mình, không bị hạn chế nơi chốn. Vương Lâm nhận ra phương pháp này cũng tồn tại ở tiên nhân trong động phủ giới (từ Thất Đạo Tông). Khác với cách khai mở Không Gian trữ vật từ bên ngoài thân thể (kiểu động phủ giới) — cách cũ không dùng được ở Tiên Cương.","congNang":["Trữ vật không hạn chế nơi chốn, khai mở từ bên trong thân thể"],"tabs":{"tienTrinh":[{"chuong":"@c1711","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Vương Lâm nhận ra nguyên lý","text":"Vương Lâm phát hiện Không Gian trữ vật tại Tiên Cương cần khai mở từ trong thân thể, xác nhận cách cũ (khe từ động phủ giới) sụp đổ tiêu tán ngay khi mở.","anchor":"Không Gian trữ vật của hắn là khai mở từ trong thân thể của mình ra"}]},"nguon":["@c1711"]},{"id":"trong-bon-nguyen","name":"Trọng bổn nguyên","cn":"","loai":"khac","loaiLabel":"Bổn nguyên","phamCap":"Cực hiếm ở Tiên Cương đại lục","hePhai":"","soHuu":["Đỗ Thanh"],"blurb":"Trọng bổn nguyên là bổn nguyên cho phép cảm ngộ và biến hóa trọng lượng mọi vật chất trong thiên địa, cực kỳ hiếm ở Tiên Cương đại lục, cần thiên tư đặc thù mới có thể minh ngộ. Đỗ Thanh nhờ thân khôi lỗi chứa một tia trọng bổn nguyên mà dần mò ra con đường cảm ngộ, đây cũng là lý do Đại Hồn Môn che chở cho hắn. Khi dung hợp với các bổn nguyên khác như hỏa hay thổ, trọng bổn nguyên mang đến uy lực khiếp sợ, đủ sức đè sụp thần thông đối thủ.","detail":"Trọng bổn nguyên là một loại bổn nguyên hiếm gặp trên Tiên Cương đại lục, bản chất nằm ở việc cảm ngộ sức nặng của mọi vật chất trong thiên địa, hiểu sâu thì có thể biến hóa nặng nhẹ theo tâm ý. Đỗ Thanh vốn không có tư cách minh ngộ trọng bổn nguyên, nhưng thân khôi lỗi của hắn chứa một tia trọng bổn nguyên nên từ từ mò ra, và đây cũng chính là lý do Đại Hồn Môn che chở cho hắn. Trọng bổn nguyên có đặc tính dung hợp mạnh mẽ: khi dung hợp với hỏa bổn nguyên, nó khiến hỏa mang trọng lượng, uy lực tăng vô số lần — liên quan đến tranh luận lâu đời trên Tiên Cương đại lục về việc hỏa có trọng lượng hay không; khi dung hợp với thổ bổn nguyên, sương mù thổ nặng như nắm cả một đại lục. Tại chương @c1717, Đỗ Thanh triển khai trọng bổn nguyên dung hợp tử hỏa và thổ bổn nguyên, đè sụp bốn thần thông","congNang":["Cảm ngộ và biến hóa trọng lượng mọi vật chất trong thiên địa, nặng nhẹ theo tâm ý","Dung hợp hỏa bổn nguyên khiến hỏa mang trọng lượng, uy lực tăng vô số lần","Dung hợp thổ bổn nguyên khiến sương mù thổ nặng như nắm cả một đại lục","Dung hợp đồng thời tử hỏa và thổ bổn nguyên, đè sụp bốn thần thông của Vương Lâm @c1717"],"nguoiTu":[{"ten":"Đỗ Thanh","tuChuong":"@c1717","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1717","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Lộ cốt lõi trọng bổn nguyên","text":"Đỗ Thanh triển khai trọng bổn nguyên dung hợp tử hỏa và thổ bổn nguyên, đè sụp bốn thần thông của Vương Lâm. Lộ rằng trọng bổn nguyên cực hiếm ở Tiên Cương, Đỗ Thanh mò ra nhờ thân khôi lỗi chứa một tia, và đây là lý do Đại Hồn Môn che chở hắn.","anchor":"Trọng bổn nguyên cảm ngộ tất cả sức nặng của vật chất trong thiên địa"}]},"nguon":["@c1717"],"uyLuc":"Triển khai trọng bổn nguyên dung hợp tử hỏa và thổ bổn nguyên, đè sụp bốn thần thông của Vương Lâm @c1717","dacDiem":"Cực hiếm ở Tiên Cương đại lục, cần thiên tư đặc thù mới minh ngộ được; bản thân không phải bổn nguyên tấn công trực tiếp mà phát huy sức mạnh qua dung hợp với các bổn nguyên khác, phú cho chúng trọng lượng, từ đó nhân uy lực lên bội phần."},{"id":"tho-bon-nguyen-do-thanh","name":"Thổ bổn nguyên","cn":"","loai":"khac","loaiLabel":"Bổn nguyên","phamCap":"","hePhai":"","soHuu":["Đỗ Thanh"],"blurb":"Bổn nguyên thổ của Đỗ Thanh, rút khí tức đại địa ngưng thành sương mù cát vàng, biến bốn phía thành đại hoang mạc.","detail":"Đỗ Thanh nhấn tay xuống đất, ánh sáng như cát vàng ngưng thành sương mù mang khí tức nồng đậm của thổ bổn nguyên. Được dung hợp trọng bổn nguyên thì sức nặng như cầm cả một đại lục.","congNang":["Rút thổ khí đại địa thành sương mù công kích","Dung hợp trọng bổn nguyên gia tăng trọng lượng cực đại"],"nguoiTu":[{"ten":"Đỗ Thanh","tuChuong":"@c1717","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1717","loai":"thi triển","importance":"normal","giaiDoan":"Đỗ Thanh triển khai thổ bổn nguyên","text":"Đỗ Thanh nhấn tay xuống đất rút thổ khí biến bốn phía thành hoang mạc, được trọng bổn nguyên gia trọng như nắm cả đại lục.","anchor":"Trong sương mù này tồn tại khí tức nồng đậm của thổ bổn nguyên"}]},"nguon":["@c1717"]},{"id":"tu-hoa-do-thanh","name":"Tử hỏa","cn":"","loai":"khac","loaiLabel":"Bổn nguyên","phamCap":"","hePhai":"","soHuu":["Đỗ Thanh"],"blurb":"Bổn nguyên hỏa của Đỗ Thanh — tử khí từ thân khôi lỗi gỗ lao ra khiến ngọn lửa hóa tử hỏa chiếu rọi thiên địa.","detail":"Khi Đỗ Thanh triển khai, tử khí trong thân khôi lỗi gỗ bốc ra khiến ngọn lửa trên thân thể lập tức biến thành tử hỏa. Được trọng bổn nguyên gia trọng thành đòn chủ lực.","congNang":["Hỏa diễm mang tử khí chiếu rọi thiên địa","Dung hợp trọng bổn nguyên tăng uy lực vô số lần"],"nguoiTu":[{"ten":"Đỗ Thanh","tuChuong":"@c1717","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1717","loai":"thi triển","importance":"normal","giaiDoan":"Đỗ Thanh lộ tử hỏa","text":"Tử khí từ thân khôi lỗi gỗ lao ra biến ngọn lửa thành tử hỏa chiếu rọi thiên địa, là đòn chủ lực khi dung hợp trọng bổn nguyên.","anchor":"ngọn lửa trong cơ thể bị tử khí lao ra, lập tức hóa tử hỏa, chiếu rọi cả thiên địa"}]},"nguon":["@c1717"]},{"id":"bon-nguyen-tu-luyen-he-thong","name":"Bổn nguyên tu luyện hệ thống","cn":"","loai":"cong-phap","loaiLabel":"Hệ thống cảnh giới / công pháp","phamCap":"Không rõ","hePhai":"Tiên Cương đại lục","soHuu":[],"blurb":"Bổn nguyên tu luyện hệ thống là hệ thống phân cấp sức mạnh bổn nguyên trên Tiên Cương đại lục, liên quan trực tiếp đến bước tiến tu vi trong Không cảnh và Không Huyền. Hệ thống gồm bốn cấp bậc từ thấp đến cao: mới xuất hiện, ngưng tụ pháp khí, đại thành, và chân thân bổn nguyên.","detail":"Bổn nguyên tu luyện hệ thống bắt nguồn từ Tiên Cương đại lục, là nền tảng đánh giá thực lực tu sĩ thông qua mức độ phát triển của bổn nguyên. Khi bổn nguyên xuất hiện, tu sĩ bước vào Không cảnh bước thứ ba; muốn đạt cảnh giới Không Huyền thì phải tự cảm ngộ hư bổn nguyên. Bổn nguyên càng nhiều, thực lực càng mạnh nhờ khả năng hấp thụ sức mạnh thiên địa. Qua suy nghĩ của Đỗ Thanh, bốn cấp bậc bổn nguyên được hé lộ: mới xuất hiện, ngưng tụ pháp khí, đại thành, và chân thân bổn nguyên. Trong đó chân thân bổn nguyên thuộc hàng truyền thuyết, cực kỳ hiếm gặp, cả đời Đỗ Thanh chỉ từng thấy trên lão tổ Đại Hồn Môn.","nguon":["@c1719"],"thuocTinh":"Bổn nguyên","nguonGoc":"Tiên Cương đại lục","cacTang":[{"ten":"Bổn nguyên mới xuất hiện","moTa":"Giai đoạn sơ khai, bổn nguyên vừa hình thành","chuong":"@c1719"},{"ten":"Ngưng tụ pháp khí","moTa":"Bổn nguyên ngưng tụ thành hình dạng pháp khí","chuong":"@c1719"},{"ten":"Đại thành","moTa":"Bổn nguyên đạt mức viên mãn","chuong":"@c1719"},{"ten":"Chân thân bổn nguyên","moTa":"Cấp truyền thuyết, cực hiếm, uy lực kinh người","chuong":"@c1719"}],"congNang":["Bổn nguyên càng nhiều thì thực lực càng mạnh, có thể hấp thụ sức mạnh thiên địa @c1719","Bổn nguyên xuất hiện cho phép tu sĩ bước vào Không cảnh bước thứ ba @c1719","Cảm ngộ hư bổn nguyên là điều kiện bắt buộc để đạt cảnh giới Không Huyền @c1719"],"tabs":{"tienTrinh":[{"chuong":"@c1719","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Lộ toàn bộ hệ thống phân cấp bổn nguyên","text":"Qua suy nghĩ của Đỗ Thanh, lộ ra bốn cấp bậc bổn nguyên: mới xuất hiện, ngưng tụ pháp khí, đại thành, chân thân bổn nguyên. Chân thân bổn nguyên là truyền thuyết, cả đời Đỗ Thanh chỉ thấy trên lão tổ Đại Hồn Môn.","anchor":"Bổn nguyên xuất hiện thì tu vi có thể bước vào trong Không cảnh bước thứ ba"}]}},{"id":"the-phu","name":"Thệ phù","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Tiên Cương đại lục","soHuu":["Đỗ Thanh"],"blurb":"Thuật pháp trên Tiên Cương đại lục, mượn pháp tắc Tiên Cương từ u minh làm chứng cho lời thề, rất ít người có thể vi phạm.","detail":"Khi sử dụng, ký hiệu màu đỏ hóa hồng quang bay lên không trung biến mất, pháp tắc Tiên Cương từ u minh giám sát lời thề. Nếu vi phạm, đạo niệm sụp đổ, linh hồn tiêu tan.","nguon":["@c1719"],"congNang":["Lời thề được pháp tắc Tiên Cương chứng giám, ràng buộc người thề @c1719"],"nguoiTu":[{"ten":"Đỗ Thanh","tuChuong":"@c1719","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1719","loai":"thi triển","importance":"normal","giaiDoan":"Đỗ Thanh dùng thệ phù thề trung thành với Vương Lâm","text":"Đỗ Thanh sử dụng thệ phù lập lời thề không có tà tâm đối với Vương Lâm, ký hiệu màu đỏ hóa hồng quang bay lên không trung biến mất, pháp tắc Tiên Cương chứng giám.","anchor":"Đây là thệ phù trên Tiên Cương đại lục, một khi sử dụng rất ít người có thể không tuân theo"}]}},{"id":"ngung-tu-bon-nguyen-chan-than","name":"Ngưng tụ bổn nguyên chân thân","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Ngưng tụ bổn nguyên chân thân là quá trình biến bổn nguyên lực thành chân thân hình người, cực kỳ gian nan và đòi hỏi lượng bổn nguyên khổng lồ cùng ý chí bổn nguyên riêng. Vương Lâm tiến hành ngưng tụ hỏa bổn nguyên chân thân thông qua hỏa cầu chứa Chu Tước, trải qua nhiều giai đoạn hấp thu phân mạch và long hồn phân mạch mới dần hoàn thiện từng bộ phận của chân thân.","detail":"Ngưng tụ bổn nguyên chân thân là quá trình chuyển hóa bổn nguyên lực ngưng tụ thành chân thân hình người. Vương Lâm tiến hành với hỏa bổn nguyên, khởi đầu bằng việc bắt quyết đánh ấn ký vào hỏa cầu chứa Chu Tước, hỏa cầu nổ tung, Chu Tước lông bốc cháy hóa hình ngư @c1720. Quá trình vô cùng gian nan: hấp thu mười sáu phân mạch cùng một mạch con và ý chí hồn mạch con mới đủ điều kiện bắt đầu, liều mạng toàn lực chỉ ngưng tụ được hai chân; sau đó hấp thu thêm một trăm bảy mươi hai long hồn phân mạch mới ngưng tụ thêm hai cánh tay, hoàn thành tứ chi, song vẫn còn thiếu phần thân và đầu. Đây là sự kiện hiếm thấy, Đỗ Thanh coi việc được chứng kiến là cơ duyên lớn. Vương Lâm sở hữu bảy đạo bổn nguyên; nếu toàn bộ đều ngưng tụ chân thân thì sức mạnh đạt tới mức không thể tưởng tượng.","congNang":["Ngưng tụ bổn nguyên lực thành chân thân hình người, từng bộ phận một (hai chân, hai cánh tay, thân, đầu)","Kích hoạt thông qua bắt quyết đánh ấn ký vào hỏa cầu chứa Chu Tước, khiến hỏa cầu nổ tung và Chu Tước lông bốc cháy hóa hình ngư @c1720"],"dacDiem":"Cực kỳ gian nan, càng về sau càng khó; cần hấp thu số lượng lớn phân mạch, long hồn phân mạch và ý chí bổn nguyên riêng mới có thể tiến hành từng giai đoạn; hiếm có người chứng kiến, được coi là cơ duyên lớn.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1720","tangDatToi":"Tứ chi hoàn thành, chưa xong thân và đầu","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1720","loai":"thi triển","importance":"major","giaiDoan":"Vương Lâm bắt đầu ngưng tụ hỏa bổn nguyên chân thân","text":"Vương Lâm bắt quyết đánh ấn ký vào hỏa cầu chứa Chu Tước, hỏa cầu nổ tung, Chu Tước lông bốc cháy hóa hình người bắt đầu ngưng tụ. Hỏa bổn nguyên không đủ, liều mạng chỉ ngưng tụ được hai chân. Triệu hồi 172 long hồn phân mạch, hấp thu ngưng tụ thêm hai cánh tay — tứ chi hoàn thành, còn thiếu thân và đầu.","anchor":"Bổn nguyên chân thân, ngưng!"}]},"nguon":["@c1720"]},{"id":"anh-tuy-tam-dong","name":"Ảnh tùy tâm động","cn":"","loai":"khac","loaiLabel":"Dị biến / Hiện tượng","phamCap":"Không rõ","hePhai":"Bổn nguyên chân thân","soHuu":["Vương Lâm"],"blurb":"Hiện tượng dị biến xuất hiện sau khi bổn nguyên chân thân ngưng tụ và thu vào mắt trái — khi bước đi phía sau xuất hiện hư ảnh đi theo.","detail":"Sau khi bổn nguyên chân thân ngưng tụ gần hoàn chỉnh và thu vào mắt trái, mắt trái hiện hai đồng tử thay vì ấn ký ngọn lửa. Khi di chuyển, phía sau xuất hiện hư ảnh theo bước. Đỗ Thanh nhận ra lão tổ Đại Hồn Môn cũng từng có hiện tượng tương tự. Vương Lâm có thể tự ý ẩn hư ảnh.","nguon":["@c1721"]},{"id":"tran-phap-tran-ap-thien-ngoai-nguu-tinh","name":"Trận pháp trấn áp thiên ngoại ngưu tinh","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Tiên Tộc (truyền thuyết)","soHuu":[],"blurb":"Trận pháp được tạo thành từ đại bộ phận địa hỏa mạch Thiên Ngưu Châu, trấn áp Nguyên Thần con thiên ngoại ngưu tinh dưới hỏa mạch.","detail":"Theo truyền thuyết, thời sơ khai Tiên Tổ Tiên Tộc giết chết thiên ngoại ngưu tinh, thân thể hóa thành Thiên Ngưu Châu, Nguyên Thần bị trấn áp dưới hỏa mạch. Đại bộ phận địa hỏa mạch gắn liền thành trận pháp này. Một thuyết khác cho rằng địa hỏa mạch chính là kinh mạch của hỏa ngưu tự biến thành, chủ mạch là kinh mạch lớn nhất xuyên qua thân hỏa ngưu.","nguonGoc":"Do Tiên Tổ Tiên Tộc bố trí, hoặc do kinh mạch hỏa ngưu tự biến thành — hai thuyết","congNang":["Trấn áp Nguyên Thần thiên ngoại ngưu tinh dưới hỏa mạch Thiên Ngưu Châu"],"tabs":{"tienTrinh":[{"chuong":"@c1722","loai":"nhắc tới","importance":"normal","giaiDoan":"Đỗ Thanh tiết lộ truyền thuyết","text":"Đỗ Thanh tiết lộ cho Vương Lâm rằng đại bộ phận địa hỏa mạch Thiên Ngưu Châu gắn liền thành trận pháp trấn áp Nguyên Thần thiên ngoại ngưu tinh, địa hỏa chủ mạch nằm ở Đại Hồn Môn.","anchor":"đại bộ phận địa hỏa mạch của Thiên Ngưu Châu nghe đồn là gắn liền thành một trận pháp, trấn áp một con thiên ngoại ngưu tinh"}]},"nguon":["@c1722"]}]};